//audio-feedback.js
// ==================== AUDIO FEEDBACK ====================
// Menggunakan Web Speech API bawaan browser (GRATIS)

class AudioFeedback {
    constructor() {
        this.speechSynthesis = window.speechSynthesis;
        this.voices = [];
        this.selectedVoice = null;
        this.isSpeaking = false;
        this.queue = [];
        this.voiceReady = false;
        this.initVoices();
    }

    initVoices() {
        if (this.speechSynthesis.getVoices().length > 0) {
            this.selectBestVoice();
        } else {
            this.speechSynthesis.addEventListener('voiceschanged', () => {
                this.selectBestVoice();
            });
        }
    }

    selectBestVoice() {
        this.voices = this.speechSynthesis.getVoices();
        
        const priorityNames = [
            'Google Bahasa Indonesia',
            'Google Indonesian',
            'Microsoft Sari',
            'Microsoft Andika',
            'Damayanti',
            'Ayu',
            'Indonesian',
            'Bahasa Indonesia'
        ];
        
        for (const name of priorityNames) {
            const found = this.voices.find(voice => voice.name.includes(name));
            if (found) {
                this.selectedVoice = found;
                console.log('Voice:', found.name);
                this.voiceReady = true;
                break;
            }
        }
        
        if (!this.selectedVoice) {
            this.selectedVoice = this.voices.find(v => v.lang.includes('id'));
            if (this.selectedVoice) {
                console.log('Voice fallback:', this.selectedVoice.name);
                this.voiceReady = true;
            }
        }
        
        if (!this.selectedVoice && this.voices.length > 0) {
            this.selectedVoice = this.voices[0];
            this.voiceReady = true;
        }
    }

    speak(text) {
        if (!text || !this.voiceReady) return;
        
        const utterance = new SpeechSynthesisUtterance(text);
        if (this.selectedVoice) utterance.voice = this.selectedVoice;
        utterance.rate = 1.2;
        utterance.pitch = 1.0;
        
        utterance.onend = () => {
            this.isSpeaking = false;
            if (this.queue.length > 0) {
                this.speak(this.queue.shift());
            }
        };
        
        if (this.isSpeaking) {
            this.queue.push(text);
            return;
        }
        
        this.isSpeaking = true;
        this.speechSynthesis.speak(utterance);
    }

    stop() {
        this.speechSynthesis.cancel();
        this.isSpeaking = false;
        this.queue = [];
    }

    // ==================== FUNGSI YANG DIPAKAI ====================
    welcome() {
        setTimeout(() => this.speak('Selamat datang di GoAbs'), 500);
    }
    
    scanSuccess(namaSiswa) {
        this.speak(`${namaSiswa}, hadir`);
    }
    
    scanTerlambat(namaSiswa, menit) {
        this.speak(`${namaSiswa}, terlambat ${menit} menit`);
    }
    
    scanFailed() {
        this.speak('QR gagal, coba lagi');
    }
    
    alreadyAbsent(namaSiswa, namaMapel) {
        this.speak(`${namaSiswa}, sudah absen di mapel ${namaMapel}`);
    }
    
    invalidQR() {
        this.speak('QR Code tidak valid');
    }
    
    studentNotFound(namaSiswa) {
        this.speak(`Siswa ${namaSiswa} tidak ditemukan`);
    }
    
    mapelNotFound() {
        this.speak('Mata pelajaran tidak ditemukan');
    }
    
    saveFailed() {
        this.speak('Gagal menyimpan absensi');
    }

    scannerStarted(namaMapel) {
        this.speak(`Scanner ${namaMapel} dimulai`);
    }

    scannerStopped() {
        this.speak('Scanner berhenti');
    }

    logout() {
        this.speak('Anda telah keluar');
    }

    mapelHidden(namaMapel) {
        this.speak(`Mata pelajaran ${namaMapel} disembunyikan`);
    }
}

const audioFeedback = new AudioFeedback();

//laporan.js
// ==================== CETAK LAPORAN ====================

function showCetakModal() {
    document.getElementById('cetakModal').style.display = 'flex';
    updateCetakFilter();
}

function closeCetakModal() {
    document.getElementById('cetakModal').style.display = 'none';
}

function updateCetakFilter() {
    const jenis = document.getElementById('cetakJenis').value;
    const container = document.getElementById('cetakFilterContainer');
    let html = '';
    
    if (jenis === 'harian') {
        html = `
            <div class="form-group">
                <label>Tanggal</label>
                <input type="date" id="cetakTanggal" value="${new Date().toISOString().split('T')[0]}">
            </div>
        `;
    } else if (jenis === 'mingguan') {
        html = `
            <div class="form-group">
                <label>Pilih Mapel</label>
                <select id="cetakMapel">${getMapelOptions()}</select>
            </div>
            <div class="form-group">
                <label>Minggu Ke</label>
                <select id="cetakMinggu">
                    <option value="1">Minggu 1</option><option value="2">Minggu 2</option>
                    <option value="3">Minggu 3</option><option value="4">Minggu 4</option>
                    <option value="5">Minggu 5</option>
                </select>
            </div>
            <div class="form-group">
                <label>Bulan & Tahun</label>
                <input type="month" id="cetakBulanMinggu" value="${new Date().toISOString().slice(0,7)}">
            </div>
        `;
    } else if (jenis === 'bulanan') {
        html = `
            <div class="form-group">
                <label>Pilih Mapel</label>
                <select id="cetakMapel">${getMapelOptions()}</select>
            </div>
            <div class="form-group">
                <label>Bulan</label>
                <input type="month" id="cetakBulan" value="${new Date().toISOString().slice(0,7)}">
            </div>
        `;
    } else if (jenis === 'semester') {
        const tahun = new Date().getFullYear();
        html = `
            <div class="form-group">
                <label>Pilih Mapel</label>
                <select id="cetakMapel">${getMapelOptions()}</select>
            </div>
            <div class="form-group">
                <label>Semester</label>
                <select id="cetakSemester">
                    <option value="1">Ganjil (Juli - Desember)</option>
                    <option value="2">Genap (Januari - Juni)</option>
                </select>
            </div>
            <div class="form-group">
                <label>Tahun Ajaran</label>
                <input type="number" id="cetakTahunSemester" value="${tahun}" min="2020" max="2030">
            </div>
        `;
    }
    container.innerHTML = html;
}

function getMapelOptions() {
    if (typeof mapelList === 'undefined') return '';
    return mapelList.map(m => `<option value="${m.idMapel}">${escapeHtml(m.namaMapel)}</option>`).join('');
}

async function generateLaporan() {
    const btnCetak = document.querySelector('#cetakModal .btn-save');
    const btnBatal = document.querySelector('#cetakModal .btn-cancel');

    showCetakSpinner(true);

    if (btnCetak) btnCetak.disabled = true;
    if (btnBatal) btnBatal.disabled = true;

    try {
        const jenis = document.getElementById('cetakJenis').value;
        const { jsPDF } = window.jspdf;
        const doc = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });

        const now = new Date();
        const tanggalCetak = now.toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' });
        const jamCetak = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' });
        const footerText = 'Dicetak dari WebApp AbsensiKu';

        const applyHeaderFooter = (pageNum, total) => {
            doc.setPage(pageNum);
            doc.setFontSize(14);
            doc.text('DAFTAR HADIR PESERTA DIDIK', doc.internal.pageSize.width / 2, 15, { align: 'center' });
            doc.setFontSize(12);
            doc.text(`Kelas: ${currentUser.namaKelas || '-'}`, doc.internal.pageSize.width / 2, 22, { align: 'center' });
            doc.text(`${currentUser.sekolah || '-'}`, doc.internal.pageSize.width / 2, 29, { align: 'center' });
            doc.setFontSize(9);
            const pageWidth = doc.internal.pageSize.width;
            const pageHeight = doc.internal.pageSize.height;
            doc.text(footerText, pageWidth / 2, pageHeight - 10, { align: 'center' });
            doc.text(`${tanggalCetak} ${jamCetak}`, pageWidth - 14, pageHeight - 10, { align: 'right' });
            doc.text(`Halaman ${pageNum} dari ${total}`, pageWidth - 14, pageHeight - 5, { align: 'right' });
        };

        let headers, body, startY = 45;

        // ========== HARIAN ==========
        if (jenis === 'harian') {
            const tanggal = document.getElementById('cetakTanggal').value;
            const dateObj = new Date(tanggal);
            const hariNama = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'][dateObj.getDay()];
            const tglFormat = dateObj.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' });

            const mapelHariIni = mapelList.filter(m => m.hari === hariNama);
            if (mapelHariIni.length === 0) {
                showToast('Tidak ada mapel di hari ini');
                return;
            }

            const res = await apiCall('getAbsensi', { uidGuru: currentUser.uid });
            if (!res.success) { showToast('Gagal ambil data'); return; }
            const absensiHarian = res.data.filter(a => a.tanggal === tanggal);

            const siswaMap = new Map();
            siswaList.forEach(s => siswaMap.set(s.idSiswa, {
                nama: s.nama, nis: s.nis, statusMapel: {}, keterangan: []
            }));

            absensiHarian.forEach(a => {
                const s = siswaMap.get(a.siswaId);
                if (!s) return;
                const mapel = mapelList.find(m => m.idMapel === a.mapelId);
                if (!mapel) return;
                const statusSingkat = a.status === 'Hadir' ? 'H' : (a.status === 'Terlambat' ? 'T' : (a.status === 'Sakit' ? 'S' : (a.status === 'Izin' ? 'I' : 'A')));
                s.statusMapel[mapel.idMapel] = statusSingkat;
                if (a.status !== 'Hadir' && a.status !== 'Terlambat') {
                    s.keterangan.push(`${mapel.namaMapel}: ${a.status}`);
                }
            });

            headers = ['No', 'Nama', 'NIS', ...mapelHariIni.map(m => m.namaMapel), 'Keterangan'];
            body = [];
            let no = 1;
            for (let s of siswaMap.values()) {
                const row = [no++, s.nama, s.nis];
                mapelHariIni.forEach(m => row.push(s.statusMapel[m.idMapel] || '-'));
                row.push(s.keterangan.join(', '));
                body.push(row);
            }

            doc.setFontSize(11);
            doc.text(`Hari/Tanggal: ${hariNama}, ${tglFormat}`, 14, 40);
            startY = 45;
        }

        // ========== MINGGUAN ==========
        else if (jenis === 'mingguan') {
            const mapelId = document.getElementById('cetakMapel').value;
            const minggu = parseInt(document.getElementById('cetakMinggu').value);
            const bulanTahun = document.getElementById('cetakBulanMinggu').value;
            if (!mapelId) { showToast('Pilih mapel'); return; }

            const mapel = mapelList.find(m => m.idMapel === mapelId);
            const [tahun, bulan] = bulanTahun.split('-').map(Number);

            const firstDay = new Date(tahun, bulan-1, 1);
            const firstMonday = new Date(firstDay);
            firstMonday.setDate(1 + (8 - firstDay.getDay()) % 7);
            const start = new Date(firstMonday);
            start.setDate(firstMonday.getDate() + (minggu - 1) * 7);
            const end = new Date(start);
            end.setDate(start.getDate() + 6);
            const startStr = start.toISOString().split('T')[0];
            const endStr = end.toISOString().split('T')[0];

            doc.setFontSize(11);
            doc.text(`Mapel: ${mapel.namaMapel}`, 14, 40);
            doc.text(`Minggu ke-${minggu} (${startStr} s/d ${endStr})`, 14, 47);

            const res = await apiCall('getAbsensi', { uidGuru: currentUser.uid });
            if (!res.success) { showToast('Gagal ambil data'); return; }
            const absensi = res.data.filter(a => a.mapelId === mapelId && a.tanggal >= startStr && a.tanggal <= endStr);

            const siswaMap = new Map();
            siswaList.forEach(s => siswaMap.set(s.idSiswa, { nama: s.nama, nis: s.nis, status: '-', ket: '' }));
            absensi.forEach(a => {
                const s = siswaMap.get(a.siswaId);
                if (!s) return;
                const singkat = a.status === 'Hadir' ? 'H' : (a.status === 'Terlambat' ? 'T' : (a.status === 'Sakit' ? 'S' : (a.status === 'Izin' ? 'I' : 'A')));
                s.status = singkat;
                if (a.status !== 'Hadir' && a.status !== 'Terlambat') s.ket = a.status;
            });

            headers = ['No', 'Nama', 'NIS', 'Kehadiran', 'Keterangan'];
            body = [];
            let no = 1;
            for (let s of siswaMap.values()) {
                body.push([no++, s.nama, s.nis, s.status, s.ket]);
            }
            startY = 52;
        }

        // ========== BULANAN ==========
        else if (jenis === 'bulanan') {
            const mapelId = document.getElementById('cetakMapel').value;
            const bulanTahun = document.getElementById('cetakBulan').value;
            if (!mapelId) { showToast('Pilih mapel'); return; }

            const mapel = mapelList.find(m => m.idMapel === mapelId);
            const [tahun, bulan] = bulanTahun.split('-').map(Number);
            const namaBulan = new Date(tahun, bulan-1).toLocaleDateString('id-ID', { month: 'long' });

            const startDate = `${tahun}-${String(bulan).padStart(2, '0')}-01`;
            const endDate = `${tahun}-${String(bulan).padStart(2, '0')}-${new Date(tahun, bulan, 0).getDate()}`;

            doc.setFontSize(11);
            doc.text(`Mapel: ${mapel.namaMapel}`, 14, 40);
            doc.text(`Bulan: ${namaBulan} ${tahun}`, 14, 47);

            const res = await apiCall('getAbsensi', { uidGuru: currentUser.uid });
            if (!res.success) { showToast('Gagal ambil data'); return; }
            const absensi = res.data.filter(a => a.mapelId === mapelId && a.tanggal >= startDate && a.tanggal <= endDate);

            const siswaMap = new Map();
            siswaList.forEach(s => siswaMap.set(s.idSiswa, {
                nama: s.nama, nis: s.nis,
                w1: '-', w2: '-', w3: '-', w4: '-', w5: '-',
                h: 0, s: 0, i: 0, a: 0
            }));

            absensi.forEach(a => {
                const s = siswaMap.get(a.siswaId);
                if (!s) return;
                const tgl = new Date(a.tanggal);
                const mingguKe = Math.ceil(tgl.getDate() / 7);
                const status = a.status === 'Hadir' ? 'H' : (a.status === 'Terlambat' ? 'T' : (a.status === 'Sakit' ? 'S' : (a.status === 'Izin' ? 'I' : 'A')));
                if (mingguKe === 1) s.w1 = status;
                else if (mingguKe === 2) s.w2 = status;
                else if (mingguKe === 3) s.w3 = status;
                else if (mingguKe === 4) s.w4 = status;
                else if (mingguKe === 5) s.w5 = status;

                if (status === 'H' || status === 'T') s.h++;
                else if (status === 'S') s.s++;
                else if (status === 'I') s.i++;
                else if (status === 'A') s.a++;
            });

            const lastDate = new Date(tahun, bulan, 0).getDate();
            const maxMinggu = Math.ceil(lastDate / 7);
            const mingguHeaders = [];
            for (let i = 1; i <= maxMinggu; i++) mingguHeaders.push(`M${i}`);
            headers = ['No', 'Nama', 'NIS', ...mingguHeaders, 'H', 'S', 'I', 'A'];
            body = [];
            let no = 1;
            for (let s of siswaMap.values()) {
                const row = [no++, s.nama, s.nis];
                if (maxMinggu >= 1) row.push(s.w1);
                if (maxMinggu >= 2) row.push(s.w2);
                if (maxMinggu >= 3) row.push(s.w3);
                if (maxMinggu >= 4) row.push(s.w4);
                if (maxMinggu >= 5) row.push(s.w5);
                row.push(s.h, s.s, s.i, s.a);
                body.push(row);
            }
            startY = 52;
        }

        // ========== SEMESTER ==========
        else if (jenis === 'semester') {
            const mapelId = document.getElementById('cetakMapel').value;
            const semester = parseInt(document.getElementById('cetakSemester').value);
            const tahun = parseInt(document.getElementById('cetakTahunSemester').value);
            if (!mapelId) { showToast('Pilih mapel'); return; }

            const mapel = mapelList.find(m => m.idMapel === mapelId);
            let startMonth, endMonth, bulanList;
            if (semester === 1) {
                startMonth = 7;
                endMonth = 12;
                bulanList = ['Jul', 'Ags', 'Sep', 'Okt', 'Nov', 'Des'];
            } else {
                startMonth = 1;
                endMonth = 6;
                bulanList = ['Jan', 'Feb', 'Mar', 'Apr', 'Mei', 'Jun'];
            }

            const startDate = `${tahun}-${String(startMonth).padStart(2, '0')}-01`;
            const lastDay = new Date(tahun, endMonth, 0).getDate();
            const endDate = `${tahun}-${String(endMonth).padStart(2, '0')}-${lastDay}`;

            doc.setFontSize(11);
            doc.text(`Mapel: ${mapel.namaMapel}`, 14, 40);
            doc.text(`Semester: ${semester === 1 ? 'Ganjil' : 'Genap'} ${tahun}/${tahun + 1}`, 14, 47);

            const res = await apiCall('getAbsensi', { uidGuru: currentUser.uid });
            if (!res.success) { showToast('Gagal ambil data'); return; }
            const absensi = res.data.filter(a => a.mapelId === mapelId && a.tanggal >= startDate && a.tanggal <= endDate);

            const siswaMap = new Map();
            siswaList.forEach(s => siswaMap.set(s.idSiswa, {
                nama: s.nama, nis: s.nis,
                bulan: {}, h: 0, s: 0, i: 0, a: 0
            }));

            absensi.forEach(a => {
                const s = siswaMap.get(a.siswaId);
                if (!s) return;
                const tgl = new Date(a.tanggal);
                const blnKey = tgl.toLocaleDateString('id-ID', { month: 'short' });
                const status = a.status === 'Hadir' ? 'H' : (a.status === 'Terlambat' ? 'T' : (a.status === 'Sakit' ? 'S' : (a.status === 'Izin' ? 'I' : 'A')));
                s.bulan[blnKey] = status;
                if (status === 'H' || status === 'T') s.h++;
                else if (status === 'S') s.s++;
                else if (status === 'I') s.i++;
                else if (status === 'A') s.a++;
            });

            headers = ['No', 'Nama', 'NIS', ...bulanList, 'H', 'S', 'I', 'A'];
            body = [];
            let no = 1;
            for (let s of siswaMap.values()) {
                const row = [no++, s.nama, s.nis];
                bulanList.forEach(bln => row.push(s.bulan[bln] || '-'));
                row.push(s.h, s.s, s.i, s.a);
                body.push(row);
            }
            startY = 52;
        }

        if (headers && body) {
            doc.autoTable({
                head: [headers],
                body: body,
                startY: startY,
                styles: { fontSize: 8 },
                margin: { top: 40 }
            });

            const totalPages = doc.internal.getNumberOfPages();
            for (let i = 1; i <= totalPages; i++) {
                applyHeaderFooter(i, totalPages);
            }
        }

        doc.save(`laporan_absensi_${jenis}.pdf`);
        closeCetakModal();
        showToast('PDF berhasil dibuat');
    } catch (error) {
        console.error(error);
        showToast('Gagal membuat PDF: ' + error.message);
    } finally {
        showCetakSpinner(false);
        if (btnCetak) btnCetak.disabled = false;
        if (btnBatal) btnBatal.disabled = false;
    }
}

// ==================== EXPORT CSV ====================
async function generateLaporanCSV() {
    const jenis = document.getElementById('cetakJenis').value;
    showCetakSpinner(true);
    const btnCSV = document.querySelector('#cetakModal .btn-save[onclick="generateLaporanCSV()"]');
    const btnPDF = document.querySelector('#cetakModal .btn-save[onclick="generateLaporan()"]');
    const btnBatal = document.querySelector('#cetakModal .btn-cancel');
    if (btnCSV) btnCSV.disabled = true;
    if (btnPDF) btnPDF.disabled = true;
    if (btnBatal) btnBatal.disabled = true;

    try {
        let csvRows = [];
        const delimiter = ';';

        csvRows.push(`"DAFTAR HADIR PESERTA DIDIK"`);
        csvRows.push(`"Kelas: ${currentUser.namaKelas || '-'}"`);
        csvRows.push(`"${currentUser.sekolah || '-'}"`);
        csvRows.push('');

        // ========== HARIAN ==========
        if (jenis === 'harian') {
            const tanggal = document.getElementById('cetakTanggal').value;
            const dateObj = new Date(tanggal);
            const hariNama = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'][dateObj.getDay()];
            const tglFormat = dateObj.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' });
            csvRows.push(`"Hari/Tanggal: ${hariNama}, ${tglFormat}"`);
            csvRows.push('');

            const mapelHariIni = mapelList.filter(m => m.hari === hariNama);
            if (mapelHariIni.length === 0) {
                showToast('Tidak ada mapel di hari ini');
                return;
            }

            const res = await apiCall('getAbsensi', { uidGuru: currentUser.uid });
            if (!res.success) { showToast('Gagal ambil data'); return; }
            const absensiHarian = res.data.filter(a => a.tanggal === tanggal);

            const siswaMap = new Map();
            siswaList.forEach(s => siswaMap.set(s.idSiswa, {
                nama: s.nama, nis: s.nis, statusMapel: {}, keterangan: []
            }));

            absensiHarian.forEach(a => {
                const s = siswaMap.get(a.siswaId);
                if (!s) return;
                const mapel = mapelList.find(m => m.idMapel === a.mapelId);
                if (!mapel) return;
                const statusSingkat = a.status === 'Hadir' ? 'H' : (a.status === 'Terlambat' ? 'T' : (a.status === 'Sakit' ? 'S' : (a.status === 'Izin' ? 'I' : 'A')));
                s.statusMapel[mapel.idMapel] = statusSingkat;
                if (a.status !== 'Hadir' && a.status !== 'Terlambat') {
                    s.keterangan.push(`${mapel.namaMapel}: ${a.status}`);
                }
            });

            const headers = ['No', 'Nama', 'NIS', ...mapelHariIni.map(m => m.namaMapel), 'Keterangan'];
            csvRows.push(headers.map(h => `"${h}"`).join(delimiter));

            let no = 1;
            for (let s of siswaMap.values()) {
                const row = [no++, s.nama, s.nis];
                mapelHariIni.forEach(m => row.push(s.statusMapel[m.idMapel] || '-'));
                row.push(s.keterangan.join(', '));
                csvRows.push(row.map(cell => `"${cell}"`).join(delimiter));
            }
        }

        // ========== MINGGUAN ==========
        else if (jenis === 'mingguan') {
            const mapelId = document.getElementById('cetakMapel').value;
            const minggu = parseInt(document.getElementById('cetakMinggu').value);
            const bulanTahun = document.getElementById('cetakBulanMinggu').value;
            if (!mapelId) { showToast('Pilih mapel'); return; }

            const mapel = mapelList.find(m => m.idMapel === mapelId);
            const [tahun, bulan] = bulanTahun.split('-').map(Number);

            const firstDay = new Date(tahun, bulan - 1, 1);
            const firstMonday = new Date(firstDay);
            firstMonday.setDate(1 + (8 - firstDay.getDay()) % 7);
            const start = new Date(firstMonday);
            start.setDate(firstMonday.getDate() + (minggu - 1) * 7);
            const end = new Date(start);
            end.setDate(start.getDate() + 6);
            const startStr = start.toISOString().split('T')[0];
            const endStr = end.toISOString().split('T')[0];

            csvRows.push(`"Mapel: ${mapel.namaMapel}"`);
            csvRows.push(`"Minggu ke-${minggu} (${startStr} s/d ${endStr})"`);
            csvRows.push('');

            const res = await apiCall('getAbsensi', { uidGuru: currentUser.uid });
            if (!res.success) { showToast('Gagal ambil data'); return; }
            const absensi = res.data.filter(a => a.mapelId === mapelId && a.tanggal >= startStr && a.tanggal <= endStr);

            const siswaMap = new Map();
            siswaList.forEach(s => siswaMap.set(s.idSiswa, { nama: s.nama, nis: s.nis, status: '-', ket: '' }));
            absensi.forEach(a => {
                const s = siswaMap.get(a.siswaId);
                if (!s) return;
                const singkat = a.status === 'Hadir' ? 'H' : (a.status === 'Terlambat' ? 'T' : (a.status === 'Sakit' ? 'S' : (a.status === 'Izin' ? 'I' : 'A')));
                s.status = singkat;
                if (a.status !== 'Hadir' && a.status !== 'Terlambat') s.ket = a.status;
            });

            const headers = ['No', 'Nama', 'NIS', 'Kehadiran', 'Keterangan'];
            csvRows.push(headers.map(h => `"${h}"`).join(delimiter));

            let no = 1;
            for (let s of siswaMap.values()) {
                const row = [no++, s.nama, s.nis, s.status, s.ket];
                csvRows.push(row.map(cell => `"${cell}"`).join(delimiter));
            }
        }

        // ========== BULANAN ==========
        else if (jenis === 'bulanan') {
            const mapelId = document.getElementById('cetakMapel').value;
            const bulanTahun = document.getElementById('cetakBulan').value;
            if (!mapelId) { showToast('Pilih mapel'); return; }

            const mapel = mapelList.find(m => m.idMapel === mapelId);
            const [tahun, bulan] = bulanTahun.split('-').map(Number);
            const namaBulan = new Date(tahun, bulan - 1).toLocaleDateString('id-ID', { month: 'long' });

            const startDate = `${tahun}-${String(bulan).padStart(2, '0')}-01`;
            const endDate = `${tahun}-${String(bulan).padStart(2, '0')}-${new Date(tahun, bulan, 0).getDate()}`;

            csvRows.push(`"Mapel: ${mapel.namaMapel}"`);
            csvRows.push(`"Bulan: ${namaBulan} ${tahun}"`);
            csvRows.push('');

            const res = await apiCall('getAbsensi', { uidGuru: currentUser.uid });
            if (!res.success) { showToast('Gagal ambil data'); return; }
            const absensi = res.data.filter(a => a.mapelId === mapelId && a.tanggal >= startDate && a.tanggal <= endDate);

            const siswaMap = new Map();
            siswaList.forEach(s => siswaMap.set(s.idSiswa, {
                nama: s.nama, nis: s.nis,
                w1: '-', w2: '-', w3: '-', w4: '-', w5: '-',
                h: 0, s: 0, i: 0, a: 0
            }));

            absensi.forEach(a => {
                const s = siswaMap.get(a.siswaId);
                if (!s) return;
                const tgl = new Date(a.tanggal);
                const mingguKe = Math.ceil(tgl.getDate() / 7);
                const status = a.status === 'Hadir' ? 'H' : (a.status === 'Terlambat' ? 'T' : (a.status === 'Sakit' ? 'S' : (a.status === 'Izin' ? 'I' : 'A')));
                if (mingguKe === 1) s.w1 = status;
                else if (mingguKe === 2) s.w2 = status;
                else if (mingguKe === 3) s.w3 = status;
                else if (mingguKe === 4) s.w4 = status;
                else if (mingguKe === 5) s.w5 = status;

                if (status === 'H' || status === 'T') s.h++;
                else if (status === 'S') s.s++;
                else if (status === 'I') s.i++;
                else if (status === 'A') s.a++;
            });

            const lastDate = new Date(tahun, bulan, 0).getDate();
            const maxMinggu = Math.ceil(lastDate / 7);
            const mingguHeaders = [];
            for (let i = 1; i <= maxMinggu; i++) mingguHeaders.push(`M${i}`);
            const headers = ['No', 'Nama', 'NIS', ...mingguHeaders, 'H', 'S', 'I', 'A'];
            csvRows.push(headers.map(h => `"${h}"`).join(delimiter));

            let no = 1;
            for (let s of siswaMap.values()) {
                const row = [no++, s.nama, s.nis];
                if (maxMinggu >= 1) row.push(s.w1);
                if (maxMinggu >= 2) row.push(s.w2);
                if (maxMinggu >= 3) row.push(s.w3);
                if (maxMinggu >= 4) row.push(s.w4);
                if (maxMinggu >= 5) row.push(s.w5);
                row.push(s.h, s.s, s.i, s.a);
                csvRows.push(row.map(cell => `"${cell}"`).join(delimiter));
            }
        }

        // ========== SEMESTER ==========
        else if (jenis === 'semester') {
            const mapelId = document.getElementById('cetakMapel').value;
            const semester = parseInt(document.getElementById('cetakSemester').value);
            const tahun = parseInt(document.getElementById('cetakTahunSemester').value);
            if (!mapelId) { showToast('Pilih mapel'); return; }

            const mapel = mapelList.find(m => m.idMapel === mapelId);
            let startMonth, endMonth, bulanList;
            if (semester === 1) {
                startMonth = 7;
                endMonth = 12;
                bulanList = ['Jul', 'Ags', 'Sep', 'Okt', 'Nov', 'Des'];
            } else {
                startMonth = 1;
                endMonth = 6;
                bulanList = ['Jan', 'Feb', 'Mar', 'Apr', 'Mei', 'Jun'];
            }

            const startDate = `${tahun}-${String(startMonth).padStart(2, '0')}-01`;
            const lastDay = new Date(tahun, endMonth, 0).getDate();
            const endDate = `${tahun}-${String(endMonth).padStart(2, '0')}-${lastDay}`;

            csvRows.push(`"Mapel: ${mapel.namaMapel}"`);
            csvRows.push(`"Semester: ${semester === 1 ? 'Ganjil' : 'Genap'} ${tahun}/${tahun + 1}"`);
            csvRows.push('');

            const res = await apiCall('getAbsensi', { uidGuru: currentUser.uid });
            if (!res.success) { showToast('Gagal ambil data'); return; }
            const absensi = res.data.filter(a => a.mapelId === mapelId && a.tanggal >= startDate && a.tanggal <= endDate);

            const siswaMap = new Map();
            siswaList.forEach(s => siswaMap.set(s.idSiswa, {
                nama: s.nama, nis: s.nis,
                bulan: {}, h: 0, s: 0, i: 0, a: 0
            }));

            absensi.forEach(a => {
                const s = siswaMap.get(a.siswaId);
                if (!s) return;
                const tgl = new Date(a.tanggal);
                const blnKey = tgl.toLocaleDateString('id-ID', { month: 'short' });
                const status = a.status === 'Hadir' ? 'H' : (a.status === 'Terlambat' ? 'T' : (a.status === 'Sakit' ? 'S' : (a.status === 'Izin' ? 'I' : 'A')));
                s.bulan[blnKey] = status;
                if (status === 'H' || status === 'T') s.h++;
                else if (status === 'S') s.s++;
                else if (status === 'I') s.i++;
                else if (status === 'A') s.a++;
            });

            const headers = ['No', 'Nama', 'NIS', ...bulanList, 'H', 'S', 'I', 'A'];
            csvRows.push(headers.map(h => `"${h}"`).join(delimiter));

            let no = 1;
            for (let s of siswaMap.values()) {
                const row = [no++, s.nama, s.nis];
                bulanList.forEach(bln => row.push(s.bulan[bln] || '-'));
                row.push(s.h, s.s, s.i, s.a);
                csvRows.push(row.map(cell => `"${cell}"`).join(delimiter));
            }
        }

        const csvString = '\uFEFF' + csvRows.join('\r\n');
        const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = `laporan_absensi_${jenis}.csv`;
        link.click();
        URL.revokeObjectURL(link.href);

        closeCetakModal();
        showToast('CSV berhasil dibuat');
    } catch (error) {
        console.error(error);
        showToast('Gagal membuat CSV: ' + error.message);
    } finally {
        showCetakSpinner(false);
        if (btnCSV) btnCSV.disabled = false;
        if (btnPDF) {
            const pdfBtn = document.querySelector('#cetakModal .btn-save[onclick="generateLaporan()"]');
            if (pdfBtn) pdfBtn.disabled = false;
        }
        if (btnBatal) btnBatal.disabled = false;
    }
}

function showCetakSpinner(show) {
    const spinner = document.getElementById('cetakSpinner');
    if (spinner) spinner.style.display = show ? 'block' : 'none';
}

// Backup & Restore Functions
async function backupData() {
    showToast('Mengambil data untuk backup...');
    try {
        const [mapelRes, siswaRes, absensiRes] = await Promise.all([
            apiCall('getMapel', { uidGuru: currentUser.uid }),
            apiCall('getSiswa', { uidGuru: currentUser.uid }),
            apiCall('getAbsensi', { uidGuru: currentUser.uid })
        ]);

        if (!mapelRes.success || !siswaRes.success || !absensiRes.success) {
            showToast('Gagal mengambil data dari server');
            return;
        }

        const backupData = {
            version: '1.0',
            timestamp: new Date().toISOString(),
            uid: currentUser.uid,
            mapel: mapelRes.data,
            siswa: siswaRes.data,
            absensi: absensiRes.data
        };

        const password = currentUser.uid.slice(0, 8);
        const encrypted = await encryptBackup(JSON.stringify(backupData), password);

        const blob = new Blob([encrypted], { type: 'application/octet-stream' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `goabsku_backup_${currentUser.name.replace(/\s/g, '_')}_${new Date().toISOString().slice(0, 10)}.goabsku`;
        a.click();
        URL.revokeObjectURL(url);
        showToast('✅ Backup berhasil diunduh');
    } catch (e) {
        console.error(e);
        showToast('❌ Gagal membuat backup');
    }
}

async function encryptBackup(text, password) {
    const enc = new TextEncoder();
    const keyMaterial = await crypto.subtle.importKey(
        'raw',
        enc.encode(password),
        { name: 'PBKDF2' },
        false,
        ['deriveKey']
    );
    const key = await crypto.subtle.deriveKey(
        {
            name: 'PBKDF2',
            salt: enc.encode('goabsku-salt'),
            iterations: 100000,
            hash: 'SHA-256'
        },
        keyMaterial,
        { name: 'AES-GCM', length: 256 },
        false,
        ['encrypt']
    );
    const iv = crypto.getRandomValues(new Uint8Array(12));
    const encrypted = await crypto.subtle.encrypt(
        { name: 'AES-GCM', iv },
        key,
        enc.encode(text)
    );
    const combined = new Uint8Array(iv.length + encrypted.byteLength);
    combined.set(iv);
    combined.set(new Uint8Array(encrypted), iv.length);
    return btoa(String.fromCharCode(...combined));
}

async function restoreData(file) {
    if (!file) return;

    if (!file.name.endsWith('.goabsku')) {
        showToast('❌ File harus berekstensi .goabsku');
        document.getElementById('restoreFileInput').value = '';
        return;
    }

    showToast('Memproses file restore...');

    try {
        const reader = new FileReader();
        reader.onload = async (e) => {
            try {
                const encryptedBase64 = e.target.result;
                const password = currentUser.uid.slice(0, 8);

                const decryptedText = await decryptBackup(encryptedBase64, password);
                const backup = JSON.parse(decryptedText);

                if (!backup.version || !backup.uid || backup.uid !== currentUser.uid) {
                    showToast('❌ File backup tidak valid atau bukan milik akun ini');
                    return;
                }

                showConfirm(
                    '⚠️ Data yang ada akan diganti dengan data dari backup. Lanjutkan?',
                    'Konfirmasi Restore',
                    async () => {
                        showToast('Mengembalikan data...');

                        const res = await apiCall('restoreBackup', {
                            uid: currentUser.uid,
                            backup: backup
                        });

                        if (res.success) {
                            showToast('✅ Data berhasil dipulihkan. Memuat ulang...');
                            localStorage.removeItem(CACHE_KEY_MAPEL);
                            localStorage.removeItem(CACHE_KEY_SISWA);
                            setTimeout(() => location.reload(), 1500);
                        } else {
                            showToast('❌ Gagal: ' + res.message);
                        }
                    }
                );
            } catch (err) {
                console.error('Restore error:', err);
                showToast('❌ File rusak, password salah, atau format tidak valid');
            }
        };
        reader.readAsText(file);
    } catch (e) {
        showToast('❌ Gagal membaca file');
    }

    document.getElementById('restoreFileInput').value = '';
}

async function decryptBackup(encryptedBase64, password) {
    const enc = new TextEncoder();

    const binaryString = atob(encryptedBase64);
    const combined = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
        combined[i] = binaryString.charCodeAt(i);
    }

    const iv = combined.slice(0, 12);
    const data = combined.slice(12);

    const keyMaterial = await crypto.subtle.importKey(
        'raw',
        enc.encode(password),
        { name: 'PBKDF2' },
        false,
        ['deriveKey']
    );

    const key = await crypto.subtle.deriveKey(
        {
            name: 'PBKDF2',
            salt: enc.encode('goabsku-salt'),
            iterations: 100000,
            hash: 'SHA-256'
        },
        keyMaterial,
        { name: 'AES-GCM', length: 256 },
        false,
        ['decrypt']
    );

    const decrypted = await crypto.subtle.decrypt(
        { name: 'AES-GCM', iv: iv },
        key,
        data
    );

    return new TextDecoder().decode(decrypted);
}

//siswa.js
// ==================== SISWA CRUD ====================

function renderSiswaList() {
    const container = document.getElementById('siswaList');
    if (!siswaList.length) {
        container.innerHTML = '<div class="empty-state">Belum ada siswa. Tambah siswa dulu!</div>';
        return;
    }
    container.innerHTML = siswaList.map(s => `
        <div class="card-item">
            <div class="card-info">
                <h4>${escapeHtml(s.nama)}</h4>
                <p>NIS: ${s.nis}</p>
                <p style="font-size:11px">Telegram: ${s.telegram || '-'}</p>
            </div>
            <div class="card-actions">
                <button class="btn-icon btn-qr" onclick="generateSingleQr('${s.idSiswa}')"><i class="fas fa-qrcode"></i></button>
                <button class="btn-icon btn-edit" onclick="editSiswa('${s.idSiswa}')"><i class="fas fa-edit"></i></button>
                <button class="btn-icon btn-delete" onclick="deleteSiswa('${s.idSiswa}')"><i class="fas fa-trash"></i></button>
            </div>
        </div>
    `).join('');
}

function filterSiswa() {
    const keyword = document.getElementById('searchSiswa').value.toLowerCase();
    const filtered = siswaList.filter(s => s.nama.toLowerCase().includes(keyword) || s.nis.toLowerCase().includes(keyword));
    const container = document.getElementById('siswaList');
    if (!filtered.length) {
        container.innerHTML = '<div class="empty-state">Tidak ada siswa ditemukan</div>';
        return;
    }
    container.innerHTML = filtered.map(s => `
        <div class="card-item">
            <div class="card-info">
                <h4>${escapeHtml(s.nama)}</h4>
                <p>NIS: ${s.nis}</p>
                <p style="font-size:11px">Telegram: ${s.telegram || '-'}</p>
            </div>
            <div class="card-actions">
                <button class="btn-icon btn-qr" onclick="generateSingleQr('${s.idSiswa}')"><i class="fas fa-qrcode"></i></button>
                <button class="btn-icon btn-edit" onclick="editSiswa('${s.idSiswa}')"><i class="fas fa-edit"></i></button>
                <button class="btn-icon btn-delete" onclick="deleteSiswa('${s.idSiswa}')"><i class="fas fa-trash"></i></button>
            </div>
        </div>
    `).join('');
}

function openSiswaModal(id = null) {
    document.getElementById('siswaModalTitle').textContent = id ? 'Edit Siswa' : 'Tambah Siswa';
    document.getElementById('siswaId').value = id || '';
    document.getElementById('siswaNis').value = '';
    document.getElementById('siswaNama').value = '';
    document.getElementById('siswaTelegram').value = '';
    if (id) {
        const siswa = siswaList.find(s => s.idSiswa === id);
        if (siswa) {
            document.getElementById('siswaNis').value = siswa.nis;
            document.getElementById('siswaNama').value = siswa.nama;
            document.getElementById('siswaTelegram').value = siswa.telegram || '';
        }
    }
    document.getElementById('siswaModal').style.display = 'flex';

    const panduanDiv = document.getElementById('panduanTelegram');
    if (panduanDiv) {
        panduanDiv.style.display = 'none';
    }

    setTimeout(() => {
        const panduanImages = document.querySelectorAll('#panduanTelegram .card-panduan img');
        panduanImages.forEach(img => {
            img.style.cursor = 'pointer';
        });
    }, 100);
}

function editSiswa(id) {
    openSiswaModal(id);
}

async function saveSiswa() {
    const id = document.getElementById('siswaId').value;
    const saveBtn = document.querySelector('#siswaModal .btn-save');

    if (saveBtn.disabled) return;

    showButtonSpinner(saveBtn, 'Menyimpan...');

    const data = {
        uidGuru: currentUser.uid,
        nis: document.getElementById('siswaNis').value,
        nama: document.getElementById('siswaNama').value,
        telegram: document.getElementById('siswaTelegram').value
    };
    if (!data.nis || !data.nama) {
        showToast('NIS dan Nama wajib diisi');
        hideButtonSpinner(saveBtn);
        return;
    }
    if (id) data.idSiswa = id;
    const res = await apiCall('saveSiswa', data);
    if (res.success) {
        localStorage.removeItem(CACHE_KEY_SISWA);
        showToast('Siswa tersimpan');
        closeSiswaModal();
        await loadDataParallel();
    } else {
        showToast('Gagal: ' + res.message);
    }
    hideButtonSpinner(saveBtn);
}

async function deleteSiswa(id) {
    const deleteBtn = event?.target?.closest('.btn-delete');
    if (deleteBtn) showButtonSpinner(deleteBtn, 'Menghapus...');

    showConfirm('Yakin ingin menghapus siswa ini?', 'Hapus Siswa', async () => {
        const res = await apiCall('deleteSiswa', { idSiswa: id, uidGuru: currentUser.uid });
        if (res.success) {
            showToast('Siswa dihapus');
            await loadDataParallel();
        } else {
            showToast('Gagal: ' + res.message);
        }
        if (deleteBtn) hideButtonSpinner(deleteBtn);
    });

    setTimeout(() => {
        if (deleteBtn?.disabled) hideButtonSpinner(deleteBtn);
    }, 100);
}

function closeSiswaModal() {
    document.getElementById('siswaModal').style.display = 'none';
    const panduanDiv = document.getElementById('panduanTelegram');
    if (panduanDiv) {
        panduanDiv.style.display = 'none';
    }
}

function generateSingleQr(siswaId) {
    const siswa = siswaList.find(s => s.idSiswa === siswaId);
    if (siswa) {
        previewQrCode(siswa);
    } else {
        showToast('Siswa tidak ditemukan');
    }
}

//mapel.js
// ==================== MAPEL CRUD ====================

function renderMapelList() {
    const dashContainer = document.getElementById('mapelList');
    const fullContainer = document.getElementById('fullMapelList');

    if (!mapelList.length) {
        dashContainer.innerHTML = fullContainer.innerHTML = '<div class="empty-state">Belum ada mata pelajaran. Tambah dulu!</div>';
        return;
    }

    function formatJam(jam) {
        if (!jam) return '-';
        if (typeof jam === 'string' && jam.includes('T')) {
            const date = new Date(jam);
            return date.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
        }
        return jam;
    }

    function getHariClass(hari) {
        const hariMap = {
            'Senin': 'hari-senin', 'Selasa': 'hari-selasa', 'Rabu': 'hari-rabu',
            'Kamis': 'hari-kamis', 'Jumat': 'hari-jumat', 'Sabtu': 'hari-sabtu',
            'Minggu': 'hari-minggu'
        };
        return hariMap[hari] || '';
    }

    const sortedByNewest = [...mapelList].sort((a, b) => {
        const dateA = new Date(a.createdAt || 0);
        const dateB = new Date(b.createdAt || 0);
        return dateB - dateA;
    });

    const latest = sortedByNewest.slice(0, 3);

    dashContainer.innerHTML = latest.map(m => `
        <div class="card-item ${m.isHidden ? 'hidden-mapel' : ''}">
            <div class="card-info" style="flex:1">
                <h4>
                    ${escapeHtml(m.namaMapel)} 
                    ${m.isHidden ? '<span class="hidden-badge"><i class="fas fa-eye-slash"></i> Tersembunyi</span>' : ''}
                    <span class="hari-badge ${getHariClass(m.hari)}">${m.hari || '-'}</span>
                </h4>
                <p>Masuk: ${formatJam(m.jamMasuk)} | Keluar: ${formatJam(m.jamKeluar)} | Toleransi: ${m.toleransi} menit</p>
            </div>
            <div class="card-actions">
                <button class="btn-icon btn-hidden ${m.isHidden ? 'active' : ''}" onclick="toggleHiddenMapel('${m.idMapel}')" title="${m.isHidden ? 'Tampilkan mapel' : 'Sembunyikan mapel'}">
                    <i class="fas ${m.isHidden ? 'fa-eye' : 'fa-eye-slash'}"></i>
                </button>
                <button class="btn-icon btn-edit" onclick="editMapel('${m.idMapel}')"><i class="fas fa-edit"></i></button>
                <button class="btn-icon btn-delete" onclick="deleteMapel('${m.idMapel}')"><i class="fas fa-trash"></i></button>
            </div>
        </div>
    `).join('');

    const urutanHari = {
        'Senin': 1, 'Selasa': 2, 'Rabu': 3, 'Kamis': 4,
        'Jumat': 5, 'Sabtu': 6, 'Minggu': 7
    };

    const sortedByDay = [...mapelList].sort((a, b) => {
        const orderA = urutanHari[a.hari] || 99;
        const orderB = urutanHari[b.hari] || 99;
        return orderA - orderB;
    });

    const renderItem = (m) => `
        <div class="card-item ${m.isHidden ? 'hidden-mapel' : ''}" data-id="${m.idMapel}" draggable="true">
            <div style="display:flex; align-items:center; width:100%;">
                <div class="drag-handle">
                    <i class="fas fa-grip-vertical"></i>
                </div>
                <div class="card-info" style="flex:1">
                    <h4>
                        ${escapeHtml(m.namaMapel)} 
                        ${m.isHidden ? '<span class="hidden-badge"><i class="fas fa-eye-slash"></i> Tersembunyi</span>' : ''}
                        <span class="hari-badge ${getHariClass(m.hari)}">${m.hari || '-'}</span>
                    </h4>
                    <p>Masuk: ${formatJam(m.jamMasuk)} | Keluar: ${formatJam(m.jamKeluar)} | Toleransi: ${m.toleransi} menit</p>
                </div>
                <div class="card-actions">
                    <button class="btn-icon btn-hidden ${m.isHidden ? 'active' : ''}" onclick="toggleHiddenMapel('${m.idMapel}')" title="${m.isHidden ? 'Tampilkan mapel' : 'Sembunyikan mapel'}">
                        <i class="fas ${m.isHidden ? 'fa-eye' : 'fa-eye-slash'}"></i>
                    </button>
                    <button class="btn-icon btn-edit" onclick="editMapel('${m.idMapel}')"><i class="fas fa-edit"></i></button>
                    <button class="btn-icon btn-delete" onclick="deleteMapel('${m.idMapel}')"><i class="fas fa-trash"></i></button>
                </div>
            </div>
        </div>
    `;

    fullContainer.innerHTML = sortedByDay.map(m => renderItem(m)).join('');

    initDragAndDrop('fullMapelList');
}

function openMapelModal(id = null) {
    document.getElementById('mapelModalTitle').textContent = id ? 'Edit Mata Pelajaran' : 'Tambah Mata Pelajaran';
    document.getElementById('mapelId').value = id || '';
    document.getElementById('mapelNama').value = '';
    document.getElementById('mapelHari').value = '';
    document.getElementById('mapelJamMasuk').value = '07:00';
    document.getElementById('mapelJamKeluar').value = '08:00';
    document.getElementById('mapelToleransi').value = '15';
    if (id) {
        const mapel = mapelList.find(m => m.idMapel === id);
        if (mapel) {
            document.getElementById('mapelNama').value = mapel.namaMapel;
            document.getElementById('mapelHari').value = mapel.hari || '';
            let jamMasuk = mapel.jamMasuk;
            let jamKeluar = mapel.jamKeluar;
            if (typeof jamMasuk === 'string' && jamMasuk.includes('T')) {
                const date = new Date(jamMasuk);
                jamMasuk = date.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
            }
            if (typeof jamKeluar === 'string' && jamKeluar.includes('T')) {
                const date = new Date(jamKeluar);
                jamKeluar = date.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
            }
            document.getElementById('mapelJamMasuk').value = jamMasuk;
            document.getElementById('mapelJamKeluar').value = jamKeluar || '08:00';
            document.getElementById('mapelToleransi').value = mapel.toleransi;
        }
    }
    document.getElementById('mapelModal').style.display = 'flex';
}

function editMapel(id) {
    openMapelModal(id);
}

async function saveMapel() {
    const id = document.getElementById('mapelId').value;
    const hari = document.getElementById('mapelHari').value;
    const saveBtn = document.querySelector('#mapelModal .btn-save');

    if (saveBtn.disabled) return;

    showButtonSpinner(saveBtn, 'Menyimpan...');

    if (!hari) {
        showToast('Pilih hari terlebih dahulu');
        hideButtonSpinner(saveBtn);
        return;
    }
    const data = {
        uidGuru: currentUser.uid,
        namaMapel: document.getElementById('mapelNama').value,
        hari: hari,
        jamMasuk: document.getElementById('mapelJamMasuk').value,
        jamKeluar: document.getElementById('mapelJamKeluar').value,
        toleransi: parseInt(document.getElementById('mapelToleransi').value)
    };
    if (!data.namaMapel) {
        showToast('Nama mata pelajaran wajib diisi');
        hideButtonSpinner(saveBtn);
        return;
    }
    if (id) data.idMapel = id;
    const res = await apiCall('saveMapel', data);
    if (res.success) {
        localStorage.removeItem(CACHE_KEY_MAPEL);
        showToast('Mapel tersimpan');
        closeMapelModal();
        await loadDataParallel();
    } else {
        showToast('Gagal: ' + res.message);
    }
    hideButtonSpinner(saveBtn);
}

async function deleteMapel(id) {
    const deleteBtn = event?.target?.closest('.btn-delete');
    if (deleteBtn) showButtonSpinner(deleteBtn, 'Menghapus...');

    showConfirm('Yakin ingin menghapus mata pelajaran ini?', 'Hapus Mapel', async () => {
        const res = await apiCall('deleteMapel', { idMapel: id, uidGuru: currentUser.uid });
        if (res.success) {
            showToast('Mapel dihapus');
            await loadDataParallel();
        } else {
            showToast('Gagal: ' + res.message);
        }
        if (deleteBtn) hideButtonSpinner(deleteBtn);
    });

    setTimeout(() => {
        if (deleteBtn?.disabled) hideButtonSpinner(deleteBtn);
    }, 100);
}

function closeMapelModal() {
    document.getElementById('mapelModal').style.display = 'none';
}

// ==================== HIDDEN MAPEL ====================
async function toggleHiddenMapel(idMapel) {
    const mapel = mapelList.find(m => m.idMapel === idMapel);
    if (!mapel) return;

    const newHiddenStatus = !mapel.isHidden;
    const actionText = newHiddenStatus ? 'disembunyikan' : 'ditampilkan';

    showConfirm(`Yakin ingin ${actionText} mata pelajaran "${mapel.namaMapel}"?`, 'Konfirmasi', async () => {
        const res = await apiCall('toggleHiddenMapel', {
            uidGuru: currentUser.uid,
            idMapel: idMapel,
            isHidden: newHiddenStatus
        });

        if (res.success) {
            mapel.isHidden = newHiddenStatus;

            localStorage.setItem(CACHE_KEY_MAPEL, JSON.stringify({
                timestamp: Date.now(),
                data: mapelList
            }));

            renderMapelList();
            updateMapelSelects();

            showToast(`Mata pelajaran "${mapel.namaMapel}" ${actionText}`);
        } else {
            showToast('Gagal: ' + res.message);
        }
    });
}

// ==================== DRAG AND DROP MAPEL ====================
let draggedItem = null;

function initDragAndDrop(containerId) {
    const container = document.getElementById(containerId);
    if (!container) return;

    container.removeEventListener('dragstart', handleDragStart);
    container.removeEventListener('dragend', handleDragEnd);
    container.removeEventListener('dragover', handleDragOver);
    container.removeEventListener('drop', handleDrop);

    container.addEventListener('dragstart', handleDragStart);
    container.addEventListener('dragend', handleDragEnd);
    container.addEventListener('dragover', handleDragOver);
    container.addEventListener('drop', handleDrop);
}

function handleDragStart(e) {
    const target = e.target.closest('.card-item');
    if (!target) return;

    draggedItem = target;
    target.classList.add('dragging');
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/html', target.innerHTML);
    e.dataTransfer.setData('text/plain', '');
}

function handleDragEnd(e) {
    const target = e.target.closest('.card-item');
    if (target) {
        target.classList.remove('dragging');
    }
    document.querySelectorAll('.card-item').forEach(item => {
        item.classList.remove('drag-over');
    });
    draggedItem = null;
}

function handleDragOver(e) {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';

    const target = e.target.closest('.card-item');
    if (!target || target === draggedItem) return;

    document.querySelectorAll('.card-item').forEach(item => {
        item.classList.remove('drag-over');
    });
    target.classList.add('drag-over');
}

function handleDrop(e) {
    e.preventDefault();

    const target = e.target.closest('.card-item');
    if (!target || !draggedItem || target === draggedItem) {
        removeDragOverClass();
        return;
    }

    const draggedId = draggedItem.dataset.id;
    const targetId = target.dataset.id;

    if (!draggedId || !targetId) {
        removeDragOverClass();
        return;
    }

    const draggedIndex = mapelList.findIndex(m => m.idMapel === draggedId);
    const targetIndex = mapelList.findIndex(m => m.idMapel === targetId);

    if (draggedIndex === -1 || targetIndex === -1) {
        removeDragOverClass();
        return;
    }

    const [movedItem] = mapelList.splice(draggedIndex, 1);
    mapelList.splice(targetIndex, 0, movedItem);

    saveMapelOrder();

    localStorage.setItem(CACHE_KEY_MAPEL, JSON.stringify({
        timestamp: Date.now(),
        data: mapelList
    }));

    renderMapelList();
    updateMapelSelects();

    removeDragOverClass();

    showToast('Urutan mata pelajaran telah diubah');
}

function removeDragOverClass() {
    document.querySelectorAll('.card-item').forEach(item => {
        item.classList.remove('drag-over');
    });
}

function saveMapelOrder() {
    const order = mapelList.map(m => m.idMapel);
    localStorage.setItem('mapel_order', JSON.stringify(order));
    console.log('Urutan mapel tersimpan ke localStorage');
}

function loadMapelOrderFromLocal() {
    const savedOrder = localStorage.getItem('mapel_order');
    if (savedOrder) {
        try {
            const order = JSON.parse(savedOrder);
            mapelList.sort((a, b) => {
                const indexA = order.indexOf(a.idMapel);
                const indexB = order.indexOf(b.idMapel);
                if (indexA === -1) return 1;
                if (indexB === -1) return -1;
                return indexA - indexB;
            });
        } catch (e) {
            console.log('Gagal memuat urutan:', e);
        }
    }
}

//absensi.js
// ==================== RIWAYAT ABSENSI ====================

async function loadRiwayatAbsensi(resetPage = true) {
    const mapelId = document.getElementById('filterMapelAbsensi').value;
    const periode = document.getElementById('filterPeriode').value;
    const bulanArsip = document.getElementById('filterBulan').value;
    let tanggalFilter = document.getElementById('filterTanggalAbsensi').value;
    const container = document.getElementById('riwayatAbsensiList');
    const prevBtn = document.getElementById('prevPageBtn');
    const nextBtn = document.getElementById('nextPageBtn');
    const pageInfoSpan = document.getElementById('pageInfo');

    if (periode === 'arsip' && !bulanArsip) {
        container.innerHTML = '<div class="empty-state">Silakan pilih bulan arsip terlebih dahulu</div>';
        if (prevBtn) prevBtn.style.display = 'none';
        if (nextBtn) nextBtn.style.display = 'none';
        if (pageInfoSpan) pageInfoSpan.textContent = '';
        return;
    }

    if (periode === 'aktif' && !tanggalFilter) {
        const today = new Date();
        const year = today.getFullYear();
        const month = String(today.getMonth() + 1).padStart(2, '0');
        const day = String(today.getDate()).padStart(2, '0');
        tanggalFilter = `${year}-${month}-${day}`;
        document.getElementById('filterTanggalAbsensi').value = tanggalFilter;
    }

    if (resetPage) {
        currentPage = 1;
        absensiPage = 0;
    }

    container.innerHTML = '<div class="spinner"></div>';
    if (prevBtn) prevBtn.disabled = true;
    if (nextBtn) nextBtn.disabled = true;
    if (pageInfoSpan) pageInfoSpan.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Memuat...';

    const res = await apiCall('getAbsensiWithArchive', {
        uidGuru: currentUser.uid,
        periode: periode,
        bulanArsip: bulanArsip,
        mapelId: mapelId || null,
        tanggal: periode === 'aktif' ? tanggalFilter : null
    });

    if (!res.success) {
        container.innerHTML = '<div class="empty-state">Gagal memuat data</div>';
        if (prevBtn) prevBtn.style.display = 'none';
        if (nextBtn) nextBtn.style.display = 'none';
        if (pageInfoSpan) pageInfoSpan.textContent = '';
        return;
    }

    let allData = res.data || [];
    allData.sort((a, b) => (b.createdAt || '').localeCompare(a.createdAt || ''));

    const totalData = allData.length;
    const totalPages = Math.ceil(totalData / ABSENSI_PER_PAGE);
    totalPagesGlobal = totalPages;
    if (currentPage < 1) currentPage = 1;
    if (currentPage > totalPages && totalPages > 0) currentPage = totalPages;

    const start = (currentPage - 1) * ABSENSI_PER_PAGE;
    const pageData = allData.slice(start, start + ABSENSI_PER_PAGE);
    const showingStart = totalData === 0 ? 0 : start + 1;
    const showingEnd = Math.min(start + ABSENSI_PER_PAGE, totalData);

    if (pageData.length === 0) {
        if (periode === 'arsip') {
            container.innerHTML = '<div class="empty-state">Tidak ada data arsip untuk bulan yang dipilih</div>';
        } else {
            const tglFormat = tanggalFilter ? new Date(tanggalFilter).toLocaleDateString('id-ID') : 'tanggal ini';
            container.innerHTML = `<div class="empty-state">Belum ada data absensi untuk ${tglFormat}</div>`;
        }
        if (prevBtn) prevBtn.style.display = 'none';
        if (nextBtn) nextBtn.style.display = 'none';
        if (pageInfoSpan) pageInfoSpan.textContent = '';
        return;
    }

    function formatTanggal(tglStr) {
        if (!tglStr) return '-';
        if (tglStr.match(/^\d{4}-\d{2}-\d{2}/)) {
            const parts = tglStr.split('-');
            return `${parts[2]}/${parts[1]}/${parts[0]}`;
        }
        return tglStr;
    }

    let html = '';
    for (const a of pageData) {
        const mapel = mapelList.find(m => m.idMapel === a.mapelId);
        const siswa = siswaList.find(s => s.idSiswa === a.siswaId);
        const namaSiswa = siswa?.nama || a.siswaId;

        let statusClass = '';
        if (a.status === 'Hadir') statusClass = 'status-hadir';
        else if (a.status === 'Terlambat') statusClass = 'status-terlambat';
        else statusClass = 'status-alpa';

        html += `
            <div class="absensi-item">
                <div>
                    <strong>${escapeHtml(namaSiswa)}</strong><br>
                    <span style="font-size:11px">${mapel ? mapel.namaMapel : '-'} | ${formatTanggal(a.tanggal)} | ${a.jam?.substring(0, 5) || '-'}</span><br>
                    <span class="${statusClass}">${a.status}</span>
                    ${a.keterangan ? `<span style="font-size:10px; color:#64748b"> (${escapeHtml(a.keterangan)})</span>` : ''}
                </div>
                <button class="btn-icon btn-delete" onclick="hapusSatuAbsensi('${a.idAbsensi}')" style="background:#fee2e2; padding:8px 12px; border-radius:12px;">
                    <i class="fas fa-trash"></i>
                </button>
            </div>
        `;
    }

    let infoHtml = '';
    if (periode === 'arsip') {
        infoHtml = `
            <div class="arsip-badge">
                <i class="fas fa-archive"></i> 
                Menampilkan data arsip bulan: ${bulanArsip} | Total: ${totalData} data
            </div>
        `;
    } else {
        infoHtml = `
            <div class="pagination-info">
                <i class="fas fa-calendar-alt"></i> Tanggal: ${formatTanggal(tanggalFilter)} | Total: ${totalData} data | Halaman ${currentPage} dari ${totalPages}
            </div>
        `;
    }

    container.innerHTML = infoHtml + html;

    if (prevBtn && nextBtn && pageInfoSpan) {
        if (totalPages > 1) {
            prevBtn.style.display = 'inline-flex';
            nextBtn.style.display = 'inline-flex';
            pageInfoSpan.style.display = 'inline-block';
            pageInfoSpan.textContent = `Halaman ${currentPage} dari ${totalPages}`;

            if (currentPage <= 1) {
                prevBtn.disabled = true;
                prevBtn.style.opacity = '0.5';
                prevBtn.style.cursor = 'not-allowed';
            } else {
                prevBtn.disabled = false;
                prevBtn.style.opacity = '1';
                prevBtn.style.cursor = 'pointer';
            }

            if (currentPage >= totalPages) {
                nextBtn.disabled = true;
                nextBtn.style.opacity = '0.5';
                nextBtn.style.cursor = 'not-allowed';
            } else {
                nextBtn.disabled = false;
                nextBtn.style.opacity = '1';
                nextBtn.style.cursor = 'pointer';
            }
        } else {
            prevBtn.style.display = 'none';
            nextBtn.style.display = 'none';
            pageInfoSpan.style.display = 'none';
        }
    }

    if (prevBtn) prevBtn.disabled = false;
    if (nextBtn) nextBtn.disabled = false;
}

function resetRiwayatPageAndLoad() {
    currentPage = 1;
    loadRiwayatAbsensi(true);
}

function onPeriodeChange() {
    currentPage = 1;
    const periode = document.getElementById('filterPeriode').value;
    const bulanSelect = document.getElementById('filterBulan');
    const tanggalInput = document.getElementById('filterTanggalAbsensi');

    if (periode === 'arsip') {
        if (bulanSelect) bulanSelect.style.display = 'block';
        if (tanggalInput) tanggalInput.style.display = 'none';
        loadDaftarBulanArsip();
    } else {
        if (bulanSelect) bulanSelect.style.display = 'none';
        if (tanggalInput) {
            tanggalInput.style.display = 'block';
            const today = new Date();
            const year = today.getFullYear();
            const month = String(today.getMonth() + 1).padStart(2, '0');
            const day = String(today.getDate()).padStart(2, '0');
            tanggalInput.value = `${year}-${month}-${day}`;
        }
    }
    resetRiwayatPageAndLoad();
}

async function loadDaftarBulanArsip() {
    const res = await apiCall('getDaftarBulanArsip', { uidGuru: currentUser.uid });
    const bulanSelect = document.getElementById('filterBulan');

    if (res.success && res.data.length > 0) {
        bulanSelect.innerHTML = '<option value="">Pilih Bulan</option>';
        res.data.forEach(bulan => {
            bulanSelect.innerHTML += `<option value="${bulan}">${bulan}</option>`;
        });
        bulanSelect.disabled = false;
    } else {
        bulanSelect.innerHTML = '<option value="">Belum ada data arsip</option>';
        bulanSelect.disabled = true;
    }
}

async function hapusSatuAbsensi(idAbsensi) {
    const deleteBtn = event?.target?.closest('.btn-delete');
    if (deleteBtn) showButtonSpinner(deleteBtn, 'Menghapus...');

    showConfirm('Hapus riwayat absensi ini?', 'Hapus Absensi', async () => {
        const res = await apiCall('deleteAbsensi', { idAbsensi, uidGuru: currentUser.uid });
        if (res.success) {
            showToast('Absensi dihapus');
            await loadRiwayatAbsensi();
            await loadRingkasanHariIni();
        } else {
            showToast('Gagal: ' + res.message);
        }
        if (deleteBtn) hideButtonSpinner(deleteBtn);
    });

    setTimeout(() => {
        if (deleteBtn?.disabled) hideButtonSpinner(deleteBtn);
    }, 100);
}

async function hapusRiwayatBerdasarkanFilter() {
    const mapelId = document.getElementById('filterMapelAbsensi').value;
    const tanggal = document.getElementById('filterTanggalAbsensi').value;
    const periode = document.getElementById('filterPeriode').value;

    console.log('Filter yang dipilih:', { mapelId, tanggal, periode });

    if (periode === 'arsip') {
        showToast('❌ Tidak dapat menghapus data arsip. Silakan hubungi admin.');
        return;
    }

    if (!mapelId && !tanggal) {
        showToast('Pilih filter mapel atau tanggal dulu');
        return;
    }

    let confirmMessage = '⚠️ Hapus semua absensi dengan filter:\n';
    if (mapelId) {
        const mapel = mapelList.find(m => m.idMapel === mapelId);
        confirmMessage += `📚 Mapel: ${mapel ? mapel.namaMapel : mapelId}\n`;
    }
    if (tanggal) {
        const dateObj = new Date(tanggal);
        const tglFormat = dateObj.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' });
        confirmMessage += `📅 Tanggal: ${tglFormat}\n`;
    }
    confirmMessage += '\n⚠️ Data yang dihapus TIDAK bisa dikembalikan!\n\nYakin ingin menghapus?';

    showConfirm(confirmMessage, 'Hapus Berdasarkan Filter', async () => {
        const deleteBtn = document.querySelector('#pageAbsensi .btn-sm[style*="background:#ef4444"]');
        if (deleteBtn) showButtonSpinner(deleteBtn, 'Menghapus...');

        showToast('⏳ Menghapus data...');

        try {
            const res = await apiCall('deleteAbsensiByFilter', {
                uidGuru: currentUser.uid,
                mapelId: mapelId || '',
                tanggal: tanggal || ''
            });

            console.log('Response delete:', res);

            if (res.success) {
                const deletedCount = res.data?.deletedCount || 0;
                if (deletedCount > 0) {
                    showToast(`✅ Berhasil menghapus ${deletedCount} data absensi`);
                } else {
                    showToast(`⚠️ Tidak ada data absensi yang cocok dengan filter`);
                }

                await loadRiwayatAbsensi(true);
                await loadRingkasanHariIni();
                updateStats();
            } else {
                showToast('❌ Gagal: ' + (res.message || 'Terjadi kesalahan'));
            }
        } catch (error) {
            console.error('Error delete:', error);
            showToast('❌ Gagal menghapus: ' + error.message);
        }

        if (deleteBtn) hideButtonSpinner(deleteBtn);
    });
}

// ==================== MANUAL ABSENSI (SAKIT/IZIN) ====================
let currentManualMapelId = null;

async function openManualAbsensiModal() {
    const mapelId = document.getElementById('filterMapelAbsensi').value;
    if (!mapelId) {
        showToast('Pilih mata pelajaran terlebih dahulu dari filter');
        return;
    }
    currentManualMapelId = mapelId;
    const mapel = mapelList.find(m => m.idMapel === mapelId);
    if (!mapel) {
        showToast('Mapel tidak ditemukan');
        return;
    }

    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const today = `${year}-${month}-${day}`;

    const absensiRes = await apiCall('getAbsensi', { uidGuru: currentUser.uid, mapelId: mapelId, tanggal: today });
    const sudahAbsenIds = absensiRes.success ? absensiRes.data.map(a => a.siswaId) : [];

    const belumAbsen = siswaList.filter(s => !sudahAbsenIds.includes(s.idSiswa));

    const select = document.getElementById('manualSiswaSelect');
    if (belumAbsen.length === 0) {
        select.innerHTML = '<option value="">-- Semua siswa sudah absen --</option>';
    } else {
        select.innerHTML = '<option value="">-- Pilih Siswa --</option>' +
            belumAbsen.map(s => `<option value="${s.idSiswa}" data-nama="${escapeHtml(s.nama)}" data-telegram="${s.telegram || ''}">${escapeHtml(s.nama)} (${s.nis})</option>`).join('');
    }

    document.getElementById('manualKeterangan').value = '';
    document.querySelector('input[name="manualStatus"][value="Sakit"]').checked = true;
    document.getElementById('manualAbsensiModal').style.display = 'flex';
}

function closeManualAbsensiModal() {
    document.getElementById('manualAbsensiModal').style.display = 'none';
    currentManualMapelId = null;
}

async function saveManualAbsensi() {
    const siswaId = document.getElementById('manualSiswaSelect').value;
    const saveBtn = document.querySelector('#manualAbsensiModal .btn-save');

    if (saveBtn.disabled) return;
    showButtonSpinner(saveBtn, 'Menyimpan...');

    if (!siswaId) {
        showToast('Pilih siswa terlebih dahulu');
        hideButtonSpinner(saveBtn);
        return;
    }
    const status = document.querySelector('input[name="manualStatus"]:checked').value;
    const keterangan = document.getElementById('manualKeterangan').value;

    const selectedOption = document.getElementById('manualSiswaSelect').selectedOptions[0];
    const siswaNama = selectedOption.dataset.nama;
    const siswaTelegram = selectedOption.dataset.telegram;
    const mapel = mapelList.find(m => m.idMapel === currentManualMapelId);

    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const today = `${year}-${month}-${day}`;

    const res = await apiCall('saveAbsensi', {
        uidGuru: currentUser.uid,
        mapelId: currentManualMapelId,
        siswaId: siswaId,
        tanggal: today,
        jam: now.toTimeString().split(' ')[0],
        status: status,
        keterangan: keterangan || (status === 'Sakit' ? 'Sakit' : 'Izin')
    });

    if (res.success) {
        showToast(`✅ ${siswaNama} - ${status}`);
        if (siswaTelegram) {
            await sendTelegramNotification(siswaTelegram, siswaNama, mapel.namaMapel, status, keterangan);
        }
        closeManualAbsensiModal();
        await loadRiwayatAbsensi();
        await loadRingkasanHariIni();
    } else {
        showToast('Gagal: ' + res.message);
    }
    hideButtonSpinner(saveBtn);
}

//libur.js
// ==================== FITUR LIBUR ====================

let liburList = [];
let isHariLibur = false;
let liburKeterangan = '';

async function loadLiburList() {
    const container = document.getElementById('liburList');
    container.innerHTML = '<div class="spinner"></div>';

    const res = await apiCall('getLibur', { uidGuru: currentUser.uid });
    if (res.success) {
        liburList = res.data || [];
        renderLiburList();
    } else {
        container.innerHTML = '<div class="empty-state">Gagal memuat data libur</div>';
    }
}

function renderLiburList() {
    const container = document.getElementById('liburList');
    if (!liburList.length) {
        container.innerHTML = '<div class="empty-state">Belum ada tanggal libur. Tambahkan sekarang!</div>';
        return;
    }

    const sorted = [...liburList].sort((a, b) => new Date(a.tanggal) - new Date(b.tanggal));

    const today = new Date();
    today.setHours(0, 0, 0, 0);

    container.innerHTML = sorted.map(l => {
        const liburDate = new Date(l.tanggal);
        const isPast = liburDate < today;
        const isToday = liburDate.getTime() === today.getTime();

        let statusBadge = '';
        if (isToday) statusBadge = '<span class="libur-badge" style="background:#22c55e">Hari Ini</span>';
        else if (isPast) statusBadge = '<span class="libur-badge" style="background:#64748b">Lewat</span>';
        else statusBadge = '<span class="libur-badge">Akan Datang</span>';

        return `
            <div class="card-item">
                <div class="card-info" style="flex:1">
                    <h4>${formatTanggalLibur(l.tanggal)} ${statusBadge}</h4>
                    <p><i class="fas fa-info-circle"></i> ${escapeHtml(l.keterangan) || 'Hari Libur'}</p>
                </div>
                <div class="card-actions">
                    <button class="btn-icon btn-edit" onclick="editLibur('${l.idLibur}')"><i class="fas fa-edit"></i></button>
                    <button class="btn-icon btn-delete" onclick="deleteLibur('${l.idLibur}')"><i class="fas fa-trash"></i></button>
                </div>
            </div>
        `;
    }).join('');
}

function formatTanggalLibur(tanggal) {
    const date = new Date(tanggal);
    const hari = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'][date.getDay()];
    const tgl = date.getDate();
    const bulan = ['Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'][date.getMonth()];
    const tahun = date.getFullYear();
    return `${hari}, ${tgl} ${bulan} ${tahun}`;
}

function openTambahLiburModal() {
    document.getElementById('liburModalTitle').textContent = 'Tambah Hari Libur';
    document.getElementById('liburId').value = '';
    document.getElementById('liburTanggal').value = '';
    document.getElementById('liburKeterangan').value = '';
    document.getElementById('liburModal').style.display = 'flex';
}

function editLibur(id) {
    const libur = liburList.find(l => l.idLibur === id);
    if (!libur) return;

    document.getElementById('liburModalTitle').textContent = 'Edit Hari Libur';
    document.getElementById('liburId').value = libur.idLibur;
    document.getElementById('liburTanggal').value = libur.tanggal;
    document.getElementById('liburKeterangan').value = libur.keterangan || '';
    document.getElementById('liburModal').style.display = 'flex';
}

function closeLiburModal() {
    document.getElementById('liburModal').style.display = 'none';
}

async function saveLibur() {
    const id = document.getElementById('liburId').value;
    const tanggal = document.getElementById('liburTanggal').value;
    const keterangan = document.getElementById('liburKeterangan').value;

    const saveBtn = document.querySelector('#liburModal .btn-save');
    if (saveBtn.disabled) return;
    showButtonSpinner(saveBtn, 'Menyimpan...');

    if (!tanggal) {
        showToast('Pilih tanggal libur');
        hideButtonSpinner(saveBtn);
        return;
    }

    const data = {
        uidGuru: currentUser.uid,
        tanggal: tanggal,
        keterangan: keterangan
    };
    if (id) data.idLibur = id;

    const res = await apiCall('saveLibur', data);
    if (res.success) {
        showToast('Hari libur tersimpan');
        closeLiburModal();
        await loadLiburList();
        await cekHariLibur();
    } else {
        showToast('Gagal: ' + res.message);
    }
    hideButtonSpinner(saveBtn);
}

async function deleteLibur(id) {
    showConfirm('Yakin ingin menghapus hari libur ini?', 'Hapus Libur', async () => {
        const res = await apiCall('deleteLibur', { idLibur: id, uidGuru: currentUser.uid });
        if (res.success) {
            showToast('Hari libur dihapus');
            await loadLiburList();
            await cekHariLibur();
        } else {
            showToast('Gagal: ' + res.message);
        }
    });
}

async function cekHariLibur() {
    const today = new Date();
    const year = today.getFullYear();
    const month = String(today.getMonth() + 1).padStart(2, '0');
    const day = String(today.getDate()).padStart(2, '0');
    const todayStr = `${year}-${month}-${day}`;

    const res = await apiCall('getLibur', { uidGuru: currentUser.uid });
    if (res.success) {
        const libur = res.data.find(l => l.tanggal === todayStr);
        isHariLibur = !!libur;
        liburKeterangan = libur ? libur.keterangan || 'Hari Libur' : '';

        showLiburBanner();
        updateScannerStatus();
    }
}

function showLiburBanner() {
    const existingBanner = document.getElementById('liburBanner');
    if (existingBanner) existingBanner.remove();

    if (isHariLibur) {
        const banner = document.createElement('div');
        banner.id = 'liburBanner';
        banner.className = 'libur-active-badge';
        banner.innerHTML = `
            <i class="fas fa-calendar-times"></i>
            <span>📅 Hari ini adalah ${liburKeterangan}. Scanner dinonaktifkan dan tidak ada absensi otomatis.</span>
        `;

        const statsGrid = document.querySelector('.stats-grid');
        if (statsGrid) {
            statsGrid.parentNode.insertBefore(banner, statsGrid);
        }
    }
}

function updateScannerStatus() {
    const scannerSelect = document.getElementById('selectedMapelScan');
    const scannerBtn = document.getElementById('btnOpenScanner');

    if (isHariLibur) {
        if (scannerSelect) {
            scannerSelect.innerHTML = '<option value="" disabled>📅 Hari Libur - Tidak ada absensi</option>';
            scannerSelect.disabled = true;
        }
        if (scannerBtn) {
            scannerBtn.disabled = true;
            scannerBtn.style.background = '#94a3b8';
            scannerBtn.style.cursor = 'not-allowed';
            scannerBtn.title = 'Tidak dapat absen karena hari libur';
        }
    } else {
        if (scannerSelect) {
            scannerSelect.disabled = false;
        }
        if (scannerBtn) {
            scannerBtn.disabled = false;
            scannerBtn.style.background = '#22c55e';
            scannerBtn.style.cursor = 'pointer';
            scannerBtn.title = '';
        }
        updateMapelSelects();
    }
}

