let cropper = null;
let currentPhotoDataUrl = null;

function openPhotoUploadModal() {
    const modal = document.getElementById('photoUploadModal');
    modal.style.display = 'flex';
    document.getElementById('photoPreview').style.display = 'none';
    document.getElementById('photoPreviewPlaceholder').style.display = 'flex';
    document.getElementById('photoInput').value = '';
    document.getElementById('savePhotoBtn').style.display = 'none';
    document.getElementById('cropContainer').style.display = 'none';
    if (cropper) {
        cropper.destroy();
        cropper = null;
    }
}

function closePhotoUploadModal() {
    document.getElementById('photoUploadModal').style.display = 'none';
    if (cropper) {
        cropper.destroy();
        cropper = null;
    }
}

function previewPhoto(input) {
    if (!input.files || !input.files[0]) return;
    const file = input.files[0];
    if (!file.type.match('image.*')) {
        showToast('File harus berupa gambar');
        return;
    }
    const reader = new FileReader();
    reader.onload = (e) => {
        const imgDataUrl = e.target.result;
        const previewImg = document.getElementById('photoPreview');
        const previewPlaceholder = document.getElementById('photoPreviewPlaceholder');
        const cropContainer = document.getElementById('cropContainer');
        const canvas = document.getElementById('cropCanvas');

        previewImg.src = imgDataUrl;
        previewImg.style.display = 'block';
        previewPlaceholder.style.display = 'none';
        cropContainer.style.display = 'block';
        document.getElementById('savePhotoBtn').style.display = 'block';

        if (cropper) cropper.destroy();
        const image = new Image();
        image.src = imgDataUrl;
        image.onload = () => {
            canvas.width = 300;
            canvas.height = 300;
            const ctx = canvas.getContext('2d');
            const size = Math.min(image.width, image.height);
            const sx = (image.width - size) / 2;
            const sy = (image.height - size) / 2;
            ctx.drawImage(image, sx, sy, size, size, 0, 0, 300, 300);
            currentPhotoDataUrl = canvas.toDataURL('image/jpeg', 0.8);
        };
    };
    reader.readAsDataURL(file);
}

async function savePhoto() {
    if (!currentPhotoDataUrl) {
        showToast('Pilih foto terlebih dahulu');
        return;
    }
    showToast('Menyimpan foto...');
    const res = await apiCall('updatePhoto', { uid: currentUser.uid, photo: currentPhotoDataUrl });
    if (res.success) {
        currentUser.photo = currentPhotoDataUrl;
        setSecureItem('guruData', currentUser);
        updateProfilePhotoDisplay(currentPhotoDataUrl);
        showToast('Foto profil berhasil diupdate');
        closePhotoUploadModal();
    } else {
        showToast('Gagal: ' + res.message);
    }
}

async function deletePhoto() {
    showConfirm('Hapus foto profil Anda?', 'Hapus Foto', async () => {
        const res = await apiCall('deletePhoto', { uid: currentUser.uid });
        if (res.success) {
            currentUser.photo = null;
            setSecureItem('guruData', currentUser);
            updateProfilePhotoDisplay(null);
            showToast('Foto profil dihapus');
            closePhotoUploadModal();
        } else {
            showToast('Gagal: ' + res.message);
        }
    });
}

function deletePhotoConfirm() {
    if (confirm('Hapus foto profil Anda?')) {
        deletePhoto();
    }
}

function updateProfilePhotoDisplay(photoDataUrl) {
    const img = document.getElementById('profilePhoto');
    const placeholder = document.getElementById('profilePhotoPlaceholder');
    if (photoDataUrl && photoDataUrl !== 'null' && photoDataUrl !== '') {
        img.src = photoDataUrl;
        img.style.display = 'block';
        placeholder.style.display = 'none';
    } else {
        img.style.display = 'none';
        placeholder.style.display = 'flex';
    }

    const profileAvatar = document.getElementById('profileAvatar');
    if (photoDataUrl && photoDataUrl !== 'null' && photoDataUrl !== '') {
        profileAvatar.innerHTML = `<img src="${photoDataUrl}" alt="Foto Profil">`;
    } else {
        profileAvatar.innerHTML = '<i class="fas fa-chalkboard-user"></i>';
    }
}

function loadProfilePhoto() {
    if (currentUser.photo && currentUser.photo !== 'null' && currentUser.photo !== '') {
        updateProfilePhotoDisplay(currentUser.photo);
    } else {
        updateProfilePhotoDisplay(null);
    }
}

// ==================== UBAH PASSWORD ====================
async function ubahPassword() {
    const saveBtn = event?.target;
    if (saveBtn?.disabled) return;
    if (saveBtn) showButtonSpinner(saveBtn, 'Memproses...');

    const oldPassword = document.getElementById('oldPassword').value;
    const newPassword = document.getElementById('newPassword').value;
    const confirmPassword = document.getElementById('confirmPassword').value;

    if (!oldPassword || !newPassword || !confirmPassword) {
        showToast('Semua field harus diisi');
        if (saveBtn) hideButtonSpinner(saveBtn);
        return;
    }
    if (newPassword.length < 6) {
        showToast('Password baru minimal 6 karakter');
        if (saveBtn) hideButtonSpinner(saveBtn);
        return;
    }
    if (newPassword !== confirmPassword) {
        showToast('Konfirmasi password tidak cocok');
        if (saveBtn) hideButtonSpinner(saveBtn);
        return;
    }
    const res = await apiCall('updatePassword', {
        uid: currentUser.uid,
        oldPassword: oldPassword,
        newPassword: newPassword
    });
    if (res.success) {
        showToast('Password berhasil diubah');
        document.getElementById('oldPassword').value = '';
        document.getElementById('newPassword').value = '';
        document.getElementById('confirmPassword').value = '';
    } else {
        showToast('Gagal: ' + res.message);
    }
    if (saveBtn) hideButtonSpinner(saveBtn);
}

