const SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbxCbCUzowT1_1gohZGrw3Snyn9DLmYswkha1-nbvgLGj7UL7ojLgGO5u3HwSNOoHM-ACg/exec';

// ========== ENKRIPSI LOCALSTORAGE ==========
function encryptData(data) {
    try {
        const jsonStr = JSON.stringify(data);
        return btoa(unescape(encodeURIComponent(jsonStr)));
    } catch (e) {
        console.error('Gagal enkripsi:', e);
        return null;
    }
}

function decryptData(encrypted) {
    try {
        const jsonStr = decodeURIComponent(escape(atob(encrypted)));
        return JSON.parse(jsonStr);
    } catch (e) {
        console.error('Gagal dekripsi:', e);
        try {
            return JSON.parse(encrypted);
        } catch {
            return null;
        }
    }
}

function setSecureItem(key, value) {
    const encrypted = encryptData(value);
    if (encrypted) localStorage.setItem(key, encrypted);
}

function getSecureItem(key) {
    const item = localStorage.getItem(key);
    if (!item) return null;
    return decryptData(item);
}

const CACHE_EXPIRY = 60 * 1000;
