async function trackDashboardAccess() {
    fetch(SCRIPT_URL, {
        method: 'POST',
        body: JSON.stringify({
            action: 'trackUser',
            email: currentUser?.email || 'Unknown',
            ip: await getClientIP().catch(() => 'Unknown'),
            userAgent: navigator.userAgent,
            referrer: document.referrer,
            timestamp: new Date().toISOString(),
            devToolsDetected: detectDevTools()
        })
    }).catch(e => console.log('Tracking error:', e));
}

function detectDevTools() {
    let detected = false;
    const threshold = 200;
    const widthThreshold = window.outerWidth - window.innerWidth > threshold;
    const heightThreshold = window.outerHeight - window.innerHeight > threshold;

    if (widthThreshold || heightThreshold) {
        detected = true;
    }

    const before = new Date();
    debugger;
    const after = new Date();
    if (after - before > 100) {
        detected = true;
    }

    return detected;
}

function detectDevToolsOnLoad() {
    const devtools = { isOpen: false };
    const element = new Image();
    Object.defineProperty(element, 'id', {
        get: function () {
            devtools.isOpen = true;
            fetch(SCRIPT_URL, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'devToolsDetected',
                    email: currentUser?.email || 'Unknown',
                    url: window.location.href,
                    timestamp: new Date().toISOString()
                })
            }).catch(e => console.log('DevTools detect error:', e));
        }
    });
    console.log(element);
}

