function changeBackground(bgType, save = true) {
    const body = document.body;
    body.style.background = '';
    body.className = '';
    if (bgType.startsWith('http') || bgType.startsWith('data:')) {
        body.style.background = `url(${bgType}) no-repeat center center fixed`;
        body.style.backgroundSize = 'cover';
    } else {
        body.classList.add(`bg-${bgType}`);
    }
    if (save && currentUser) {
        apiCall('updateBackground', { uid: currentUser.uid, background: bgType }).then(res => {
            if (res.success) {
                currentUser.background = bgType;
                setSecureItem('guruData', currentUser);
            }
        });
    }
    document.querySelectorAll('.bg-option').forEach(opt => opt.classList.remove('selected'));
    const selectedOpt = document.querySelector(`.bg-option.bg-${bgType}`);
    if (selectedOpt) selectedOpt.classList.add('selected');
}

function uploadBackgroundImage(input) {
    if (!input.files || !input.files[0]) return;
    const file = input.files[0];
    if (!file.type.match('image.*')) {
        showToast('File harus berupa gambar');
        return;
    }
    showToast('Memproses gambar...');
    compressImage(file, 200, async (compressedDataUrl) => {
        document.body.style.background = `url(${compressedDataUrl}) no-repeat center center fixed`;
        document.body.style.backgroundSize = 'cover';
        const res = await apiCall('updateBackground', { uid: currentUser.uid, background: compressedDataUrl });
        if (res.success) {
            currentUser.background = compressedDataUrl;
            setSecureItem('guruData', currentUser);
            showToast('Background berhasil diubah');
        } else {
            showToast('Gagal menyimpan: ' + res.message);
        }
        input.value = '';
    });
}

function resetBackground() {
    document.body.style.background = '';
    document.body.className = '';
    document.body.classList.add('bg-default');
    apiCall('updateBackground', { uid: currentUser.uid, background: 'default' }).then(res => {
        if (res.success) {
            currentUser.background = 'default';
            setSecureItem('guruData', currentUser);
            showToast('Background reset ke default');
        } else {
            showToast('Gagal reset: ' + res.message);
        }
    });
    document.querySelectorAll('.bg-option').forEach(opt => opt.classList.remove('selected'));
    document.querySelector('.bg-option.bg-default')?.classList.add('selected');
}

function compressImage(file, maxSizeKB = 200, callback) {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (e) => {
        const img = new Image();
        img.src = e.target.result;
        img.onload = () => {
            const canvas = document.createElement('canvas');
            let width = img.width;
            let height = img.height;
            const maxWidth = 800;
            if (width > maxWidth) {
                height = (height * maxWidth) / width;
                width = maxWidth;
            }
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d');
            ctx.drawImage(img, 0, 0, width, height);
            let quality = 0.7;
            let resultDataUrl = canvas.toDataURL('image/jpeg', quality);
            while (resultDataUrl.length > maxSizeKB * 1024 && quality > 0.3) {
                quality -= 0.1;
                resultDataUrl = canvas.toDataURL('image/jpeg', quality);
            }
            callback(resultDataUrl);
        };
    };
}

