// ==================== BROADCAST ====================
let siswaWithTelegram = [];

function openBroadcastModal() {
    siswaWithTelegram = siswaList.filter(s => {
        if (!s.telegram) return false;
        const telegramStr = String(s.telegram).trim();
        return telegramStr !== '' && telegramStr !== 'null' && telegramStr !== 'undefined';
    });

    if (siswaWithTelegram.length === 0) {
        showToast('⚠️ Tidak ada siswa yang memiliki Chat ID Telegram. Tambahkan Chat ID terlebih dahulu.');
        return;
    }

    document.getElementById('broadcastTitle').value = '';
    document.getElementById('broadcastMessage').value = '';
    document.getElementById('broadcastPreview').style.display = 'none';
    document.getElementById('broadcastProgress').style.display = 'none';

    const previewDiv = document.getElementById('broadcastPreview');
    previewDiv.innerHTML = `
        <p><i class="fas fa-users"></i> <strong class="count">${siswaWithTelegram.length}</strong> orangtua siswa akan menerima pesan ini:</p>
        <div style="margin-top:8px; max-height:100px; overflow-y:auto">
            ${siswaWithTelegram.slice(0, 5).map(s => `<p>📱 ${escapeHtml(s.nama)} (${s.nis})</p>`).join('')}
            ${siswaWithTelegram.length > 5 ? `<p><small>...dan ${siswaWithTelegram.length - 5} lainnya</small></p>` : ''}
        </div>
    `;
    previewDiv.style.display = 'block';

    document.getElementById('broadcastModal').style.display = 'flex';
}

function closeBroadcastModal() {
    document.getElementById('broadcastModal').style.display = 'none';
}

async function sendBroadcastMessage() {
    const title = document.getElementById('broadcastTitle').value.trim();
    const message = document.getElementById('broadcastMessage').value.trim();

    if (!title && !message) {
        showToast('Judul atau isi pesan harus diisi');
        return;
    }

    if (siswaWithTelegram.length === 0) {
        showToast('Tidak ada penerima pesan');
        return;
    }

    const sendBtn = document.getElementById('sendBroadcastBtn');
    const progressDiv = document.getElementById('broadcastProgress');
    const originalText = sendBtn.innerHTML;

    sendBtn.disabled = true;
    sendBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Mengirim...';
    progressDiv.style.display = 'block';
    progressDiv.innerHTML = `
        <div class="spinner" style="width:30px;height:30px"></div>
        <p style="font-size:12px; color:#64748b; margin-top:8px">Memulai pengiriman...</p>
    `;

    let successCount = 0;
    let failCount = 0;
    let failedList = [];

    const fullMessage = title ? `📢 *${title}*\n\n${message}` : message;

    for (let i = 0; i < siswaWithTelegram.length; i++) {
        const siswa = siswaWithTelegram[i];
        let chatId = String(siswa.telegram).trim();

        if (!chatId || chatId === '' || chatId === 'null' || chatId === 'undefined') {
            failCount++;
            failedList.push(`${siswa.nama} (${siswa.nis}) - ID tidak valid`);
            continue;
        }

        try {
            const result = await sendTelegramMessageDirect(chatId, fullMessage);
            if (result.success) {
                successCount++;
            } else {
                failCount++;
                failedList.push(`${siswa.nama} (${siswa.nis})`);
                console.error(`Gagal kirim ke ${siswa.nama}:`, result.error);
            }
        } catch (error) {
            failCount++;
            failedList.push(`${siswa.nama} (${siswa.nis})`);
            console.error(`Error kirim ke ${siswa.nama}:`, error);
        }

        progressDiv.innerHTML = `
            <div class="spinner" style="width:30px;height:30px"></div>
            <p style="font-size:12px; color:#64748b; margin-top:8px">
                Mengirim... ${i + 1}/${siswaWithTelegram.length}
                <br>✅ Berhasil: ${successCount} | ❌ Gagal: ${failCount}
            </p>
        `;

        await new Promise(resolve => setTimeout(resolve, 200));
    }

    progressDiv.innerHTML = `
        <div style="text-align:center">
            <i class="fas fa-check-circle" style="color:#16a34a; font-size:32px; margin-bottom:8px"></i>
            <p style="font-weight:bold">Pengiriman Selesai!</p>
            <p style="font-size:12px">✅ Berhasil: ${successCount} orangtua</p>
            <p style="font-size:12px">❌ Gagal: ${failCount} orangtua</p>
            ${failCount > 0 ? `<p style="font-size:10px; color:#ef4444; margin-top:8px">Gagal dikirim ke: ${failedList.slice(0, 3).join(', ')}${failedList.length > 3 ? ` dan ${failedList.length - 3} lainnya` : ''}</p>` : ''}
        </div>
    `;

    setTimeout(() => {
        sendBtn.disabled = false;
        sendBtn.innerHTML = originalText;

        if (successCount > 0) {
            showToast(`✅ Pesan terkirim ke ${successCount} orangtua`);
        }
        if (failCount > 0) {
            showToast(`⚠️ Gagal kirim ke ${failCount} orangtua`);
        }

        setTimeout(() => {
            if (successCount > 0 || failCount > 0) {
                closeBroadcastModal();
            }
        }, 2000);
    }, 3000);
}

async function sendTelegramMessageDirect(chatId, message) {
    const res = await apiCall('sendTelegramMessage', {
        chatId: chatId,
        message: message
    });

    if (res.success) {
        return { success: true };
    } else {
        console.error('Telegram API Error:', res.message);
        return { success: false, error: res.message };
    }
}

