// ==================== SCANNER QR ====================
function startScanner() {
    const selectedMapelId = document.getElementById('selectedMapelScan').value;
    if (!selectedMapelId) {
        showToast('Pilih mata pelajaran terlebih dahulu');
        return;
    }
    if (scannerActive) {
        showToast('Scanner sudah aktif');
        return;
    }

    const mapel = mapelList.find(m => m.idMapel === selectedMapelId);
    document.getElementById('scanInfoMapel').textContent = mapel ? mapel.namaMapel : 'Mapel';

    if (typeof audioFeedback !== 'undefined' && mapel) {
        audioFeedback.scannerStarted(mapel.namaMapel);
    }

    document.getElementById('displayNama').textContent = '-';
    document.getElementById('displayNIS').textContent = '-';
    const statusEl = document.getElementById('displayStatus');
    statusEl.textContent = '-';
    statusEl.style.background = 'transparent';
    statusEl.style.color = 'white';
    setScanStatusMessage('Siap memindai');

    const bottomNav = document.querySelector('.bottom-nav');
    if (bottomNav) bottomNav.style.display = 'none';

    const scannerDiv = document.getElementById('scannerFullscreen');
    scannerDiv.style.display = 'flex';
    document.body.style.overflow = 'hidden';

    if (html5QrCode && scannerActive) {
        html5QrCode.stop().then(() => {
            startNewScanner(selectedMapelId);
        }).catch(() => {
            startNewScanner(selectedMapelId);
        });
    } else {
        startNewScanner(selectedMapelId);
    }
}

function startNewScanner(selectedMapelId) {
    if (html5QrCode) {
        try {
            html5QrCode.clear();
        } catch (e) { }
    }

    html5QrCode = new Html5Qrcode("qr-reader-fullscreen");
    currentFacingMode = "environment";

    html5QrCode.start(
        { facingMode: currentFacingMode },
        {
            fps: 10,
            qrbox: { width: 280, height: 280 },
            aspectRatio: 1.0
        },
        async (decodedText) => {
            processScanResult(decodedText, selectedMapelId);
        },
        (errorMessage) => {
            if (errorMessage.includes('NotFoundException')) {
                return;
            }
            console.log('Scan error:', errorMessage);
        }
    ).catch(err => {
        console.error('Gagal akses kamera:', err);
        showToast('Gagal akses kamera: ' + err.message);
        stopScanner();
    });

    scannerActive = true;
}

function stopScanner() {
    if (typeof audioFeedback !== 'undefined') {
        audioFeedback.scannerStopped();
    }

    const bottomNav = document.querySelector('.bottom-nav');
    if (bottomNav) bottomNav.style.display = 'flex';

    document.body.style.overflow = '';
    const scannerDiv = document.getElementById('scannerFullscreen');
    scannerDiv.style.display = 'none';

    document.getElementById('displayNama').textContent = '-';
    document.getElementById('displayNIS').textContent = '-';
    const statusEl = document.getElementById('displayStatus');
    statusEl.textContent = '-';
    statusEl.style.background = 'transparent';
    statusEl.style.color = 'white';
    setScanStatusMessage('Siap memindai');

    if (html5QrCode && scannerActive) {
        try {
            html5QrCode.stop().then(() => {
                scannerActive = false;
                html5QrCode.clear();
            }).catch(e => {
                console.log('Stop scanner error:', e);
                scannerActive = false;
            });
        } catch (e) {
            console.log('Stop scanner error:', e);
            scannerActive = false;
        }
    } else {
        scannerActive = false;
    }
}

function flipCamera() {
    if (!scannerActive) return;

    currentFacingMode = currentFacingMode === "environment" ? "user" : "environment";

    if (html5QrCode) {
        html5QrCode.stop().then(() => {
            const selectedMapelId = document.getElementById('selectedMapelScan').value;
            html5QrCode.start(
                { facingMode: currentFacingMode },
                { fps: 10, qrbox: { width: 280, height: 280 } },
                async (decodedText) => {
                    processScanResult(decodedText, selectedMapelId);
                },
                (errorMessage) => { }
            ).catch(err => {
                setScanStatusMessage('❌ Gagal flip kamera: ' + err, true);
                currentFacingMode = currentFacingMode === "environment" ? "user" : "environment";
                if (html5QrCode) {
                    html5QrCode.start(
                        { facingMode: currentFacingMode },
                        { fps: 10, qrbox: { width: 280, height: 280 } },
                        async (decodedText) => { processScanResult(decodedText, selectedMapelId); },
                        (errorMessage) => { }
                    ).catch(e => setScanStatusMessage('❌ Gagal restart kamera', true));
                }
            });
        });
    }
}

function setScanStatusMessage(msg, isError = false) {
    const el = document.getElementById('scanStatusMessage');
    if (el) {
        el.textContent = msg;
        el.style.color = isError ? '#f87171' : '#94a3b8';
    }
}

async function processScanResult(data, mapelId) {
    let qrData, siswa;
    try {
        qrData = JSON.parse(data);
    } catch (e) {
        setScanStatusMessage('❌ QR Code tidak valid', true);
        if (typeof audioFeedback !== 'undefined') audioFeedback.invalidQR();
        return;
    }

    if (!qrData.siswaId || !qrData.nis || !qrData.nama) {
        setScanStatusMessage('❌ QR Code bukan QR siswa', true);
        if (typeof audioFeedback !== 'undefined') audioFeedback.invalidQR();
        return;
    }

    const nowTime = Date.now();
    const lastScan = lastScanTime.get(qrData.siswaId);
    if (lastScan && (nowTime - lastScan) < 5000) {
        setScanStatusMessage(`⏳ Tunggu sesaat untuk scan lagi`, true);
        return;
    }
    lastScanTime.set(qrData.siswaId, nowTime);
    setScanStatusMessage(`📱 Memproses ${qrData.nama}...`);

    siswa = siswaList.find(s => s.idSiswa === qrData.siswaId);
    if (!siswa) {
        setScanStatusMessage(`❌ Siswa ${qrData.nama} tidak ditemukan`, true);
        if (typeof audioFeedback !== 'undefined') audioFeedback.studentNotFound(qrData.nama);
        return;
    }

    const mapel = mapelList.find(m => m.idMapel === mapelId);
    if (!mapel) {
        setScanStatusMessage(`❌ Mata pelajaran tidak ditemukan`, true);
        if (typeof audioFeedback !== 'undefined') audioFeedback.mapelNotFound();
        return;
    }

    if (mapel.isHidden) {
        setScanStatusMessage(`❌ Mata pelajaran "${mapel.namaMapel}" sedang disembunyikan`, true);
        if (typeof audioFeedback !== 'undefined') audioFeedback.mapelHidden(mapel.namaMapel);
        return;
    }

    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const today = `${year}-${month}-${day}`;

    const absensiRes = await apiCall('getAbsensi', { uidGuru: currentUser.uid, mapelId: mapelId, tanggal: today });
    if (absensiRes.success && absensiRes.data.some(a => a.siswaId === siswa.idSiswa)) {
        setScanStatusMessage(`⚠️ ${siswa.nama} sudah absen untuk mapel ini`, true);
        if (typeof audioFeedback !== 'undefined') audioFeedback.alreadyAbsent(siswa.nama, mapel.namaMapel);
        return;
    }

    let jamMasukStr = mapel.jamMasuk;
    if (jamMasukStr instanceof Date || (typeof jamMasukStr === 'object' && jamMasukStr.toISOString)) {
        const date = new Date(jamMasukStr);
        if (!isNaN(date.getTime())) {
            jamMasukStr = date.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
        }
    } else if (typeof jamMasukStr === 'string' && jamMasukStr.includes('T')) {
        const date = new Date(jamMasukStr);
        if (!isNaN(date.getTime())) {
            jamMasukStr = date.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
        }
    }

    const [jamMasukHour, jamMasukMinute] = jamMasukStr.split(':').map(Number);
    const jamMasukMenit = jamMasukHour * 60 + jamMasukMinute;
    const nowMenit = now.getHours() * 60 + now.getMinutes();
    const toleransi = parseInt(mapel.toleransi) || 0;
    const selisih = nowMenit - jamMasukMenit;

    let status = 'Hadir';
    let keterangan = '';
    let terlambatMenit = 0;

    if (selisih > toleransi) {
        status = 'Terlambat';
        terlambatMenit = selisih;
        keterangan = `Terlambat ${selisih} menit`;
    }

    document.getElementById('displayNama').textContent = siswa.nama;
    document.getElementById('displayNIS').textContent = `NIS: ${siswa.nis}`;
    const statusEl = document.getElementById('displayStatus');
    statusEl.textContent = status;
    statusEl.style.background = status === 'Hadir' ? '#16a34a' : (status === 'Terlambat' ? '#d97706' : '#dc2626');
    statusEl.style.color = 'white';

    if (typeof audioFeedback !== 'undefined') {
        if (status === 'Hadir') {
            audioFeedback.scanSuccess(siswa.nama);
        } else if (status === 'Terlambat') {
            audioFeedback.scanTerlambat(siswa.nama, terlambatMenit);
        }
    }

    const saveRes = await apiCall('saveAbsensi', {
        uidGuru: currentUser.uid,
        mapelId: mapelId,
        siswaId: siswa.idSiswa,
        tanggal: today,
        jam: now.toTimeString().split(' ')[0],
        status: status,
        keterangan: keterangan
    });

    if (saveRes.success) {
        setScanStatusMessage(`✅ ${siswa.nama} - ${status}`);
        if (status === 'Terlambat' && siswa.telegram) {
            sendTelegramNotification(siswa.telegram, siswa.nama, mapel.namaMapel, status, keterangan);
        }
        await loadRingkasanHariIni();
    } else {
        setScanStatusMessage(`❌ Gagal simpan ${siswa.nama}: ${saveRes.message}`, true);
        if (typeof audioFeedback !== 'undefined') audioFeedback.saveFailed();
        lastScanTime.delete(qrData.siswaId);
    }
}

async function sendTelegramNotification(telegramId, siswaNama, mapelNama, status, keterangan) {
    if (!telegramId) return;
    const message = `⚠️ *NOTIFIKASI ABSENSI*\n\nNama: ${siswaNama}\nMata Pelajaran: ${mapelNama}\nStatus: ${status}\n${keterangan ? 'Keterangan: ' + keterangan : ''}\nWaktu: ${new Date().toLocaleString()}`;

    const res = await apiCall('sendTelegramMessage', {
        chatId: telegramId,
        message: message
    });

    if (!res.success) {
        console.log('Gagal kirim notifikasi:', res.message);
    }
}

// ==================== QR CODE GENERATOR ====================
function showQrOptions() {
    const siswaSelect = document.getElementById('qrSiswaSelect');
    siswaSelect.innerHTML = '<option value="all">📦 Semua Siswa (Download Massal PDF)</option><option disabled>---</option>';
    siswaList.forEach(s => {
        siswaSelect.innerHTML += `<option value="${s.idSiswa}">👤 ${escapeHtml(s.nama)} (${s.nis})</option>`;
    });
    document.getElementById('qrOptionsModal').style.display = 'flex';
}

function closeQrOptionsModal() {
    document.getElementById('qrOptionsModal').style.display = 'none';
}

function generateAndDownloadQr() {
    const siswaId = document.getElementById('qrSiswaSelect').value;
    if (siswaId === 'all') {
        if (!siswaList.length) { showToast('Tidak ada siswa'); return; }
        showToast('Membuat PDF dengan 4 QR per halaman...');
        generateMultipleQrPdf(siswaList);
        closeQrOptionsModal();
    } else {
        const siswa = siswaList.find(s => s.idSiswa === siswaId);
        if (siswa) previewQrCode(siswa);
        closeQrOptionsModal();
    }
}

async function generateMultipleQrPdf(siswaList) {
    if (typeof window.jspdf === 'undefined') {
        showToast('Library PDF belum siap, refresh halaman');
        return;
    }

    const { jsPDF } = window.jspdf;
    const doc = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4'
    });

    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();

    const margin = 10;
    const cardWidth = (pageWidth - (margin * 3)) / 2;
    const cardHeight = (pageHeight - (margin * 3)) / 2;

    const positions = [
        { x: margin, y: margin },
        { x: margin + cardWidth + margin, y: margin },
        { x: margin, y: margin + cardHeight + margin },
        { x: margin + cardWidth + margin, y: margin + cardHeight + margin }
    ];

    for (let i = 0; i < siswaList.length; i++) {
        const siswa = siswaList[i];
        const position = positions[i % 4];
        const isFirstOnPage = (i % 4 === 0);

        if (isFirstOnPage && i !== 0) {
            doc.addPage();
        }

        const qrData = JSON.stringify({
            siswaId: siswa.idSiswa,
            nis: siswa.nis,
            nama: siswa.nama
        });
        const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=${encodeURIComponent(qrData)}`;

        const img = await loadImage(qrUrl);

        const qrSize = Math.min(cardWidth * 0.6, cardHeight * 0.5);
        const qrX = position.x + (cardWidth - qrSize) / 2;
        const qrY = position.y + 15;

        doc.setDrawColor(239, 68, 68);
        doc.setLineWidth(0.5);
        doc.setLineDashPattern([3, 3], 0);
        doc.rect(position.x, position.y, cardWidth, cardHeight, 'S');

        doc.setLineDashPattern([], 0);

        doc.setFontSize(10);
        doc.setTextColor(239, 68, 68);
        doc.text("✂️", position.x + 3, position.y + 5);
        doc.text("✂️", position.x + cardWidth - 5, position.y + 5);
        doc.text("✂️", position.x + 3, position.y + cardHeight - 3);
        doc.text("✂️", position.x + cardWidth - 5, position.y + cardHeight - 3);

        doc.addImage(img, 'PNG', qrX, qrY, qrSize, qrSize);

        doc.setFontSize(12);
        doc.setTextColor(0, 0, 0);
        doc.setFont('helvetica', 'bold');
        doc.text(siswa.nama, position.x + cardWidth / 2, qrY + qrSize + 8, { align: 'center' });

        doc.setFontSize(10);
        doc.setFont('helvetica', 'normal');
        doc.text(`NIS: ${siswa.nis}`, position.x + cardWidth / 2, qrY + qrSize + 15, { align: 'center' });

        doc.setFontSize(8);
        doc.setTextColor(100, 100, 100);
        doc.text("Scan QR untuk absensi", position.x + cardWidth / 2, qrY + qrSize + 22, { align: 'center' });

        if (currentUser && currentUser.sekolah) {
            doc.setFontSize(7);
            doc.setTextColor(150, 150, 150);
            doc.text(currentUser.sekolah, position.x + cardWidth / 2, position.y + cardHeight - 5, { align: 'center' });
        }
    }

    doc.save(`QR_Siswa_${new Date().toISOString().split('T')[0]}.pdf`);
    showToast('PDF berhasil didownload dengan 4 QR per halaman');
}

function loadImage(url) {
    return new Promise((resolve, reject) => {
        const img = new Image();
        img.crossOrigin = "Anonymous";
        img.onload = () => resolve(img);
        img.onerror = reject;
        img.src = url;
    });
}

async function previewQrCode(siswa) {
    const qrData = JSON.stringify({ siswaId: siswa.idSiswa, nis: siswa.nis, nama: siswa.nama });
    const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=${encodeURIComponent(qrData)}`;
    currentQrData = { siswa, qrData, qrUrl };
    document.getElementById('previewTitle').innerHTML = `QR Code - ${escapeHtml(siswa.nama)}`;
    document.getElementById('qrPreviewContainer').innerHTML = `
        <div class="qr-student-card">
            <img src="${qrUrl}" alt="QR Code" id="previewQrImg">
            <h4>${escapeHtml(siswa.nama)}</h4>
            <p>NIS: ${siswa.nis}</p>
            <p style="font-size:10px; margin-top:8px;">Scan untuk absensi (pilih mapel terlebih dahulu)</p>
        </div>
    `;
    document.getElementById('qrPreviewModal').style.display = 'flex';
}

function closeQrPreviewModal() {
    document.getElementById('qrPreviewModal').style.display = 'none';
}

function downloadCurrentQr() {
    if (currentMultipleQrData && currentMultipleQrData.length > 0) {
        generateMultipleQrPdf(currentMultipleQrData);
        closeQrPreviewModal();
    } else if (currentQrData) {
        downloadQrAsPdf();
    }
}

function downloadQrAsPdf() {
    if (!currentQrData) return;
    const { siswa, qrUrl } = currentQrData;

    if (typeof window.jspdf === 'undefined') {
        showToast('Library PDF belum siap, refresh halaman');
        return;
    }

    const { jsPDF } = window.jspdf;

    const cardWidth = 105;
    const cardHeight = 148.5;

    const doc = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: [cardWidth, cardHeight]
    });

    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();

    doc.setDrawColor(239, 68, 68);
    doc.setLineWidth(0.5);
    doc.setLineDashPattern([3, 3], 0);
    doc.rect(2, 2, pageWidth - 4, pageHeight - 4, 'S');

    doc.setLineDashPattern([], 0);
    doc.setFontSize(8);
    doc.setTextColor(239, 68, 68);
    doc.text("✂️", 5, 7);
    doc.text("✂️", pageWidth - 7, 7);
    doc.text("✂️", 5, pageHeight - 5);
    doc.text("✂️", pageWidth - 7, pageHeight - 5);

    const qrSize = 50;
    const qrX = (pageWidth - qrSize) / 2;
    const qrY = 20;

    doc.addImage(img, 'PNG', qrX, qrY, qrSize, qrSize);

    doc.setFontSize(12);
    doc.setTextColor(0, 0, 0);
    doc.setFont('helvetica', 'bold');
    doc.text(siswa.nama, pageWidth / 2, qrY + qrSize + 8, { align: 'center' });

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`NIS: ${siswa.nis}`, pageWidth / 2, qrY + qrSize + 16, { align: 'center' });

    doc.setFontSize(8);
    doc.setTextColor(100, 100, 100);
    doc.text("Scan QR untuk absensi", pageWidth / 2, qrY + qrSize + 24, { align: 'center' });

    if (currentUser && currentUser.sekolah) {
        doc.setFontSize(7);
        doc.setTextColor(150, 150, 150);
        let sekolahText = currentUser.sekolah;
        if (sekolahText.length > 25) {
            sekolahText = sekolahText.substring(0, 22) + '...';
        }
        doc.text(sekolahText, pageWidth / 2, pageHeight - 6, { align: 'center' });
    }

    doc.save(`QR_${siswa.nis}_${siswa.nama}.pdf`);
    showToast('PDF berhasil didownload');
    closeQrPreviewModal();
}

// ==================== Toggle Panduan Telegram ====================
function togglePanduanTelegram() {
    const panduanDiv = document.getElementById('panduanTelegram');
    if (panduanDiv.style.display === 'none' || panduanDiv.style.display === '') {
        panduanDiv.style.display = 'block';
        addClickEventToPanduanImages();
    } else {
        panduanDiv.style.display = 'none';
    }
}

function addClickEventToPanduanImages() {
    const panduanImages = document.querySelectorAll('#panduanTelegram .card-panduan img');
    panduanImages.forEach((img, index) => {
        img.removeEventListener('click', handleImageClick);
        img.addEventListener('click', handleImageClick);
        img.style.cursor = 'pointer';
        img.style.transition = 'transform 0.2s';
        img.addEventListener('mouseenter', () => {
            img.style.transform = 'scale(1.02)';
        });
        img.addEventListener('mouseleave', () => {
            img.style.transform = 'scale(1)';
        });
    });
}

function handleImageClick(event) {
    event.stopPropagation();
    const img = event.target;
    const parentCard = img.closest('.card-panduan');
    const caption = parentCard.querySelector('.caption')?.innerText || 'Panduan Telegram';
    const imageSrc = img.src;
    openLightbox(imageSrc, caption);
}

// Start init
init();
